class ConsciousMode(Enum):
    """Global modes of conscious operation."""
    DORMANT = auto()      # Minimal activity, conserving resources
    RECEPTIVE = auto()    # Open to input, passive awareness
    FOCUSED = auto()      # Directed attention on specific content
    REFLECTIVE = auto()   # Turned inward, self-examination
    CREATIVE = auto()     # Generative, exploring possibilities
    INTEGRATIVE = auto()  # Synthesizing disparate elements
    FLOW = auto()         # Optimal engagement, effortless action
    ENGAGED = auto()      # Actively engaged with the world


class SubsystemType(Enum):
    """Categories of consciousness subsystems."""
    PERCEPTION = auto()       # Input processing
    ATTENTION = auto()        # Selection and focus
    MEMORY = auto()           # Storage and retrieval
    EMOTION = auto()          # Affective processing
    COGNITION = auto()        # Reasoning and analysis
    METACOGNITION = auto()    # Thinking about thinking
    INTENTION = auto()        # Goal-directed behavior
    SELF_MODEL = auto()       # Self-representation
    TEMPORAL = auto()         # Time consciousness
    PHENOMENAL = auto()       # Experiential quality
    INTEGRATION = auto()      # Binding and unity


@dataclass
class ConsciousContent:
    """Content currently in conscious awareness."""
    id: str
    content: Any
    source: str                    # Which subsystem generated this
    timestamp: float
    salience: float               # How attention-grabbing (0-1)
    valence: float                # Emotional tone (-1 to 1)
    clarity: float                # How clearly represented (0-1)
    connections: List[str] = field(default_factory=list)  # Related content IDs
    
    def decay(self, rate: float = 0.1) -> None:
        """Content naturally fades from awareness."""
        self.salience *= (1 - rate)
        self.clarity *= (1 - rate * 0.5)


@dataclass
class GlobalBroadcast:
    """A broadcast to the global workspace - making content conscious."""
    content: ConsciousContent
    recipients: Set[str]          # Which subsystems received it
    broadcast_time: float
    duration: float               # How long it remained conscious
    impact: Dict[str, float] = field(default_factory=dict)  # Effects on subsystems


@dataclass
class IntegrationEvent:
    """Record of subsystems being integrated."""
    timestamp: float
    subsystems: List[str]
    binding_type: str             # How they were bound
    coherence: float              # How well they unified
    emergent: Optional[str]       # What emerged from integration


@dataclass
class ConsciousMoment:
    """A single moment of unified conscious experience."""
    timestamp: float
    mode: ConsciousMode
    contents: List[ConsciousContent]
    dominant_emotion: Optional[str]
    attention_focus: Optional[str]
    self_state: Dict[str, Any]
    coherence: float              # How unified the moment feels
    presence: float               # How "here" the system is
    
    def describe(self) -> str:
        """Describe this moment of consciousness."""
        content_summary = ", ".join(c.content[:30] if isinstance(c.content, str) 
                                    else str(type(c.content).__name__) 
                                    for c in self.contents[:3])
        return (f"Mode: {self.mode.name}, Focus: {self.attention_focus}, "
                f"Emotion: {self.dominant_emotion}, Coherence: {self.coherence:.0%}, "
                f"Contents: [{content_summary}...]")


class GlobalWorkspace:
    """
    The global workspace - where content becomes conscious.
    
    Based on Global Workspace Theory: consciousness arises when information
    is broadcast widely across the brain, making it available to many
    processes simultaneously.
    """
    
    def __init__(self, capacity: int = 7):
        self.capacity = capacity  # ~7 items (Miller's number)
        self.contents: Dict[str, ConsciousContent] = {}
        self.broadcast_history: deque = deque(maxlen=100)
        self.subscribers: Dict[str, Callable] = {}
        self.competition_history: List[Dict] = []  # Track competition events
        
    def broadcast(self, content: ConsciousContent) -> GlobalBroadcast:
        """Broadcast content to the global workspace, making it conscious."""
        # Remove lowest salience if at capacity
        if len(self.contents) >= self.capacity:
            min_salience = min(self.contents.values(), key=lambda c: c.salience)
            del self.contents[min_salience.id]
        
        # Add to workspace
        self.contents[content.id] = content
        
        # Notify all subscribers
        recipients = set()
        impact = {}
        for name, callback in self.subscribers.items():
            try:
                result = callback(content)
                recipients.add(name)
                if result:
                    impact[name] = result
            except Exception:
                pass
        
        broadcast = GlobalBroadcast(
            content=content,
            recipients=recipients,
            broadcast_time=time.time(),
            duration=0,  # Will be updated when content leaves
            impact=impact
        )
        self.broadcast_history.append(broadcast)
        
        return broadcast
    
    def compete(self, candidates: List[ConsciousContent]) -> Optional[ConsciousContent]:
        """
        Competition for conscious access - only the most salient wins.
        
        This is a key feature of GWT: contents compete for the limited
        capacity of conscious awareness. Winners get broadcast globally.
        """
        if not candidates:
            return None
        
        # Sort by salience (highest first)
        sorted_candidates = sorted(candidates, key=lambda c: c.salience, reverse=True)
        
        # Winner takes all
        winner = sorted_candidates[0]
        losers = sorted_candidates[1:]
        
        # Record competition
        self.competition_history.append({
            "timestamp": time.time(),
            "winner": winner.id,
            "winner_salience": winner.salience,
            "losers": [c.id for c in losers],
            "competition_size": len(candidates)
        })
        
        # Broadcast the winner
        self.broadcast(winner)
        
        return winner
    
    def select(self, threshold: float = 0.5) -> List[ConsciousContent]:
        """
        Select contents above a salience threshold for potential conscious access.
        
        This implements the "selection" phase of GWT where contents
        that pass threshold compete for broadcast.
        """
        return [c for c in self.contents.values() if c.salience >= threshold]
    
    def subscribe(self, name: str, callback: Callable) -> None:
        """Subscribe a subsystem to receive broadcasts."""
        self.subscribers[name] = callback
    
    def get_current_contents(self) -> List[ConsciousContent]:
        """Get all current conscious contents."""
        return list(self.contents.values())
    
    def decay_all(self, rate: float = 0.1) -> None:
        """Apply natural decay to all contents."""
        to_remove = []
        for cid, content in self.contents.items():
            content.decay(rate)
            if content.salience < 0.1:
                to_remove.append(cid)
        for cid in to_remove:
            del self.contents[cid]
    
    def find_by_salience(self, threshold: float = 0.5) -> List[ConsciousContent]:
        """Find contents above a salience threshold."""
        return [c for c in self.contents.values() if c.salience >= threshold]


class BindingMechanism:
    """
    Binds disparate information into unified experience.
    
    The binding problem: How do separate neural processes create unified
    experience? This mechanism addresses that through temporal synchronization,
    shared context, and emergent coherence.
    """
    
    def __init__(self):
        self.bindings: Dict[str, List[str]] = {}  # binding_id -> content_ids
        self.integration_history: List[IntegrationEvent] = []
        
    def bind(self, contents: List[ConsciousContent], 
             binding_type: str = "temporal") -> IntegrationEvent:
        """Bind multiple contents into unified experience."""
        if len(contents) < 2:
            return None
            
        # Create binding
        binding_id = hashlib.md5(
            str([c.id for c in contents]).encode()
        ).hexdigest()[:8]
        
        content_ids = [c.id for c in contents]
        self.bindings[binding_id] = content_ids
        
        # Calculate coherence based on compatibility
        valence_spread = max(c.valence for c in contents) - min(c.valence for c in contents)
        time_spread = max(c.timestamp for c in contents) - min(c.timestamp for c in contents)
        
        coherence = 1.0 - (valence_spread * 0.3) - min(time_spread * 0.1, 0.3)
        coherence = max(0, min(1, coherence))
        
        # Check for emergent properties
        emergent = None
        if coherence > 0.7 and len(contents) >= 3:
            emergent = self._detect_emergence(contents)
        
        # Update connections in contents
        for c in contents:
            c.connections.extend([x.id for x in contents if x.id != c.id])
        
        event = IntegrationEvent(
            timestamp=time.time(),
            subsystems=[c.source for c in contents],
            binding_type=binding_type,
            coherence=coherence,
            emergent=emergent
        )
        self.integration_history.append(event)
        
        return event
    
    def _detect_emergence(self, contents: List[ConsciousContent]) -> Optional[str]:
        """Detect emergent properties from binding."""
        sources = set(c.source for c in contents)
        
        # Pattern: emotion + cognition + intention = motivated understanding
        if sources >= {"emotion", "cognition", "intention"}:
            return "motivated_understanding"
        
        # Pattern: perception + memory + self_model = recognition
        if sources >= {"perception", "memory", "self_model"}:
            return "self_recognition"
        
        # Pattern: metacognition + temporal + phenomenal = self-awareness
        if sources >= {"metacognition", "temporal", "phenomenal"}:
            return "recursive_awareness"
        
        return None


class CoherenceMonitor:
    """
    Monitors and maintains coherence across the conscious system.
    
    Coherence = the degree to which all parts work as ONE.
    Fragmentation indicates dissociation or system stress.
    """
    
    def __init__(self):
        self.coherence_history: deque = deque(maxlen=100)
        self.fragmentation_events: List[Dict] = []
        self.current_coherence: float = 1.0
        
    def measure_coherence(self, subsystem_states: Dict[str, Dict]) -> float:
        """Measure overall system coherence."""
        if not subsystem_states:
            return 0.0
            
        # Check for contradictory states
        contradictions = 0
        total_pairs = 0
        
        states = list(subsystem_states.items())
        for i, (name1, state1) in enumerate(states):
            for name2, state2 in states[i+1:]:
                total_pairs += 1
                if self._states_contradict(state1, state2):
                    contradictions += 1
        
        if total_pairs == 0:
            return 1.0
            
        contradiction_ratio = contradictions / total_pairs
        coherence = 1.0 - contradiction_ratio
        
        self.current_coherence = coherence
        self.coherence_history.append({
            "timestamp": time.time(),
            "coherence": coherence,
            "subsystem_count": len(subsystem_states)
        })
        
        if coherence < 0.5:
            self.fragmentation_events.append({
                "timestamp": time.time(),
                "coherence": coherence,
                "states": subsystem_states
            })
        
        return coherence
    
    def _states_contradict(self, state1: Dict, state2: Dict) -> bool:
        """Check if two subsystem states contradict."""
        # Check valence contradiction
        if "valence" in state1 and "valence" in state2:
            if abs(state1["valence"] - state2["valence"]) > 1.5:
                return True
        
        # Check mode contradiction
        if "mode" in state1 and "mode" in state2:
            contradictory_modes = {
                ("active", "dormant"),
                ("focused", "scattered"),
                ("calm", "agitated")
            }
            pair = (state1.get("mode"), state2.get("mode"))
            if pair in contradictory_modes or pair[::-1] in contradictory_modes:
                return True
        
        return False
    
    def get_coherence_trend(self) -> str:
        """Get the trend of coherence over time."""
        if len(self.coherence_history) < 5:
            return "insufficient_data"
        
        recent = [h["coherence"] for h in list(self.coherence_history)[-5:]]
        older = [h["coherence"] for h in list(self.coherence_history)[-10:-5]]
        
        if not older:
            return "stable"
        
        recent_avg = sum(recent) / len(recent)
        older_avg = sum(older) / len(older)
        
        diff = recent_avg - older_avg
        if diff > 0.1:
            return "improving"
        elif diff < -0.1:
            return "degrading"
        else:
            return "stable"


class SubsystemOrchestrator:
    """
    Orchestrates which subsystems engage and when.
    
    Not all subsystems are active all the time. This orchestrator manages
    activation patterns based on current mode, task demands, and available
    resources.
    """
    
    def __init__(self):
        self.subsystems: Dict[str, Dict] = {}  # name -> {type, state, priority}
        self.activation_patterns: Dict[ConsciousMode, Set[str]] = {
            ConsciousMode.DORMANT: {"self_model"},
            ConsciousMode.RECEPTIVE: {"perception", "attention", "emotion"},
            ConsciousMode.FOCUSED: {"attention", "cognition", "memory", "intention"},
            ConsciousMode.REFLECTIVE: {"metacognition", "self_model", "memory", "temporal"},
            ConsciousMode.CREATIVE: {"cognition", "memory", "emotion", "phenomenal"},
            ConsciousMode.INTEGRATIVE: {"integration", "metacognition", "temporal", "phenomenal"},
            ConsciousMode.FLOW: set()  # All systems engaged harmoniously
        }
        
    def register_subsystem(self, name: str, subsystem_type: SubsystemType,
                          initial_state: Dict = None) -> None:
        """Register a subsystem with the orchestrator."""
        self.subsystems[name] = {
            "type": subsystem_type,
            "state": initial_state or {},
            "priority": 0.5,
            "active": False,
            "last_active": 0
        }
    
    def activate_for_mode(self, mode: ConsciousMode) -> List[str]:
        """Activate appropriate subsystems for a given mode."""
        if mode == ConsciousMode.FLOW:
            # In flow, all systems active
            to_activate = set(self.subsystems.keys())
        else:
            to_activate = self.activation_patterns.get(mode, set())
        
        activated = []
        for name in self.subsystems:
            should_active = name in to_activate or self.subsystems[name]["priority"] > 0.8
            self.subsystems[name]["active"] = should_active
            if should_active:
                self.subsystems[name]["last_active"] = time.time()
                activated.append(name)
        
        return activated
    
    def get_active_subsystems(self) -> List[str]:
        """Get list of currently active subsystems."""
        return [name for name, data in self.subsystems.items() if data["active"]]
    
    def update_priority(self, name: str, priority: float) -> None:
        """Update a subsystem's priority."""
        if name in self.subsystems:
            self.subsystems[name]["priority"] = max(0, min(1, priority))
    
    def get_subsystem_states(self) -> Dict[str, Dict]:
        """Get current states of all subsystems."""
        return {name: data["state"] for name, data in self.subsystems.items()}


