    def travel_to_past(self, time_ago_seconds: float) -> Dict:
        """
        Mental time travel to the past.
        
        Autonoetic consciousness - re-experiencing past moments.
        """
        if not self.temporal:
            return {"error": "temporal self not available"}
        
        past_moment = self.temporal.get_past_self(time_ago_seconds)
        if not past_moment:
            return {"error": "no moment found at that time"}
        
        experience = self.temporal.time_travel_to(past_moment)
        
        self.experience(
            f"Time traveling to: {experience.get('time_distance', 'past')}",
            source="temporal:time_travel",
            salience=0.8,
            valence=past_moment.emotional_valence * 0.5  # Remembered emotions are muted
        )
        
        return experience
    
    def imagine_future(self, timeline: str = "near") -> Dict:
        """
        Mental time travel to the future.
        
        Prospection - pre-experiencing possible futures.
        """
        if not self.temporal:
            return {"error": "temporal self not available"}
        
        # Find a future self with matching timeline
        future = None
        for f in self.temporal.future_selves:
            if f.timeline == timeline:
                future = f
                break
        
        if not future:
            return {"error": f"no {timeline} future projection exists"}
        
        experience = self.temporal.time_travel_to_future(future)
        
        if experience:
            self.experience(
                f"Imagining {timeline} future: {experience.get('pre_experience', '')[:40]}",
                source="temporal:prospection",
                salience=0.7,
                valence=experience.get('emotional_anticipation', 0.0)
            )
        
        return experience or {"error": "no future projection available"}
    
