    def compare_past_present(self, time_ago_seconds: float) -> Dict:
        """
        Compare past self to present self.
        
        Self-change awareness - am I the same being?
        """
        if not self.temporal:
            return {"error": "temporal self not available"}
        
        past = self.temporal.get_past_self(time_ago_seconds)
        present = self.temporal.present_moment
        
        if past and present:
            return self.temporal.compare_selves(past, present)
        
        return {"error": "cannot compare - missing moments"}
    
