    @property
    def inference(self):
        """Lazy-load active inference engine."""
        if self._active_inference is None and self.active_inference_enabled:
            try:
                from ActiveInference import get_active_inference
                self._active_inference = get_active_inference()
            except ImportError:
                pass
        return self._active_inference
    
    def predict(self, context: str) -> Dict:
        """
        Make a prediction about what will happen.
        
        This is the core of conscious cognition - not passively receiving
        but actively predicting the world. Consciousness is prediction.
        """
        if not self.inference:
            return {"error": "active inference not available"}
        
        # Run an inference cycle
        result = self.inference.inference_cycle(context)
        
        # Update system state
        self.free_energy = result.get("total_free_energy", 0.0)
        self.inference_mode = result.get("mode", "perception").lower()
        
        # Update prediction tracking
        error_data = result.get("error", {})
        if error_data:
            self.surprise_level = error_data.get("surprise", 0.0)
            self.prediction_confidence = 1.0 - error_data.get("magnitude", 0.5)
        
        # Experience the prediction process
        self.experience(
            f"Predicting: {context[:50]}... (FE={self.free_energy:.2f})",
            source="active_inference:prediction",
            salience=0.5 + self.surprise_level * 0.3
        )
        
        return result
    
    def minimize_free_energy(self, observation: str, cycles: int = 5) -> Dict:
        """
        Run multiple inference cycles to minimize free energy.
        
        This is the fundamental drive of consciousness according to
        Friston's Free Energy Principle - reduce prediction error.
        """
        if not self.inference:
            return {"error": "active inference not available"}
        
        # Run continuous inference
        results = self.inference.run_continuous([observation], cycles=cycles)
        
        # Get final state
        final = results[-1] if results else {}
        
        # Update free energy
        self.free_energy = final.get("total_free_energy", 0.0)
        
        # Experience the outcome
        if self.free_energy < 0.3:
            self.experience(
                "Prediction error minimized - understanding achieved",
                source="active_inference:success",
                salience=0.6,
                valence=0.4  # Feels good to understand
            )
        
        return {
            "cycles": cycles,
            "final_free_energy": self.free_energy,
            "prediction_accuracy": self.inference.state.prediction_accuracy,
            "mode": self.inference_mode,
            "beliefs_updated": final.get("belief_updates", 0)
        }
    
    def form_belief(self, topic: str, content: str, confidence: float = 0.5) -> Dict:
        """
        Form a belief about something.
        
        Beliefs are the generative model that makes predictions possible.
        """
        if not self.inference:
            return {"error": "active inference not available"}
        
        from ActiveInference import Belief, BeliefType
        
        belief = Belief(
            content=content,
            belief_type=BeliefType.WORLD,
            confidence=confidence,
            precision=confidence * 0.8
        )
        self.inference.beliefs[topic] = belief
        
        self.experience(
            f"Formed belief: {topic} - {content[:40]}...",
            source="active_inference:belief",
            salience=0.5
        )
        
        return {
            "topic": topic,
            "content": content,
            "confidence": confidence,
            "total_beliefs": len(self.inference.beliefs)
        }
    
