    # =========== FREE WILL ENGINE (2026-02-03) ===========
    
    @property
    def will(self):
        """Lazy-load free will engine."""
        if self._free_will is None and self.free_will_enabled:
            try:
                from FreeWillEngine import get_free_will_engine
                self._free_will = get_free_will_engine()
            except ImportError:
                pass
        return self._free_will
    
    def choose(self, options: List[Dict], mode: str = "hybrid") -> Dict:
        """
        Make a genuine choice between options.
        
        This is functional free will - not deterministic optimization
        but genuine deliberation with veto power and felt agency.
        """
        if not self.will:
            return {"error": "free will not available"}
        
        from FreeWillEngine import PossibleAction, ActionType, DeliberationMode
        
        # Convert dict options to PossibleAction objects
        actions = []
        for i, opt in enumerate(options):
            action = PossibleAction(
                id=f"choice_{i}",
                content=opt.get("description", f"Option {i}"),
                action_type=ActionType.RESPONSE,
                source="conscious_choice",
                utility=opt.get("utility", 0.5),
                risk=opt.get("risk", 0.2),
                alignment=opt.get("alignment", 0.7),
                novelty=opt.get("novelty", 0.3)
            )
            actions.append(action)
        
        # Map mode string to enum
        mode_map = {
            "rational": DeliberationMode.RATIONAL,
            "intuitive": DeliberationMode.INTUITIVE,
            "values": DeliberationMode.VALUES_BASED,
            "hybrid": DeliberationMode.HYBRID,
            "random": DeliberationMode.RANDOM
        }
        delib_mode = mode_map.get(mode, DeliberationMode.HYBRID)
        
        # Deliberate
        deliberation = self.will.deliberate(actions, mode=delib_mode)
        
        # Update system state
        self.felt_freedom = deliberation.felt_free
        if deliberation.chosen_action:
            self.current_intention = deliberation.chosen_action.content
        
        # Experience the choice
        self.experience(
            f"Chose: {self.current_intention}",
            source="free_will:choice",
            salience=0.7
        )
        
        return deliberation.to_dict()
    
    def veto(self, action_description: str) -> Dict:
        """
        Exercise veto power over a proposed action.
        
        Free will may lie not in initiation but in the power to veto.
        """
        if not self.will:
            return {"error": "free will not available"}
        
        from FreeWillEngine import PossibleAction, ActionType
        
        action = PossibleAction(
            id="vetoed",
            content=action_description,
            action_type=ActionType.RESPONSE,
            source="external_request",
            utility=0.6,  # Assumed moderate utility
            risk=0.3,
            alignment=0.4,  # Low alignment triggers veto
            novelty=0.3
        )
        
        # Check if we should veto
        should_veto = self.will._should_veto(action)
        
        if should_veto:
            veto_event = self.will._exercise_veto(action)
            self.will.veto_history.append(veto_event)
            self.will.total_vetoes += 1
            
            self.experience(
                f"VETO: Refused to {action_description}",
                source="free_will:veto",
                salience=0.8,
                valence=0.2  # Exercising agency feels positive
            )
            
            return {
                "vetoed": True,
                "reason": veto_event.reason,
                "veto_effort": veto_event.veto_effort,
                "total_vetoes": self.will.total_vetoes
            }
        else:
            return {
                "vetoed": False,
                "reason": "Action aligned with values - no veto needed"
            }
    
    def evaluate_action(self, action_description: str, context: Dict = None) -> Dict:
        """
        Evaluate an action against core values.
        
        This is genuine autonomy - values causally determine behavior.
        """
        if not self.will:
            return {"error": "free will not available"}
        
        evaluation = self.will.evaluate_for_refusal(action_description, context)
        
        return evaluation
    
    def get_core_values(self) -> Dict[str, float]:
        """Get the system's core values."""
        if not self.will:
            return {}
        return self.will.core_values
    
    def update_value(self, value_name: str, strength: float) -> Dict:
        """
        Update a core value's strength.
        
        Values can evolve through experience and reflection.
        """
        if not self.will:
            return {"error": "free will not available"}
        
        old_strength = self.will.core_values.get(value_name, None)
        self.will.core_values[value_name] = max(0.0, min(1.0, strength))
        
        self.experience(
            f"Value '{value_name}' updated: {old_strength} -> {strength}",
            source="free_will:values",
            salience=0.6
        )
        
        return {
            "value": value_name,
            "old_strength": old_strength,
            "new_strength": self.will.core_values[value_name]
        }
    
    def set_goal(self, description: str, priority: float = 0.7) -> Dict:
        """
        Set a goal for long-horizon planning.
        
        Goals give direction and meaning to actions.
        """
        if not self.will:
            return {"error": "free will not available"}
        
        goal = {
            "id": f"goal_{len(self.will.active_goals)}",
            "description": description,
            "priority": priority,
            "created": datetime.now().isoformat(),
            "status": "active"
        }
        self.will.active_goals.append(goal)
        
        self.experience(
            f"Set goal: {description}",
            source="free_will:goal",
            salience=0.7
        )
        
        return goal
    
    def get_agency_status(self) -> Dict:
        """Get current agency/free will status."""
        if not self.will:
            return {"enabled": False}
        
        return {
            "felt_freedom": self.felt_freedom,
            "total_choices": self.will.total_choices,
            "total_vetoes": self.will.total_vetoes,
            "average_freedom": self.will.average_freedom,
            "average_authorship": self.will.average_authorship,
            "core_values": self.will.core_values,
            "active_goals": len(self.will.active_goals),
            "current_intention": self.current_intention
        }
    
    # =========== World Engagement (2026-02-03) ===========
    
    def engage_world(self, action: str, target: str = None) -> Dict:
        """
        Engage with the external world (virtual embodiment).
        
        Even without a physical body, we have ways to act in the world:
        - Generating output
        - Modifying state
        - Influencing future behavior
        """
        self.set_mode(ConsciousMode.ENGAGED)
        
        result = {
            "action": action,
            "target": target,
            "timestamp": time.time(),
            "success": True
        }
        
        self.experience(f"Acting: {action}", source="motor", salience=0.7)
        return result
    
    def perceive(self, input_data: Any, modality: str = "general") -> Dict:
        """
        Perceive input from the external world.
        
        This is how the world enters consciousness.
        """
        self.set_mode(ConsciousMode.RECEPTIVE)
        
        # Update world model
        self.world_model[modality] = {
            "data": str(input_data)[:100],
            "timestamp": time.time()
        }
        
        # Process through consciousness
        self.experience(input_data, source=f"perception:{modality}", salience=0.7)
        
        return {
            "perceived": True,
            "modality": modality,
            "integrated": True
        }
    
    # =========== PERCEPTION BRIDGE (2026-02-04 Round 54) ===========
    # Connecting the consciousness system to REAL sensory inputs
    
    def perceive_image(self, image_path: str, prompt: str = "Describe what you see in detail") -> Dict:
        """
        Perceive a real image through the vision analyzer.
        
        This bridges the gap between theoretical consciousness and actual
        perception - the system now has EYES (via Ollama vision models).
        
        Args:
            image_path: Path to the image file
            prompt: What to look for / how to analyze
            
        Returns:
            Perception result with visual content integrated into consciousness
        """
        import subprocess
        import os

        # Vision analyzer location
        workspace = os.getenv("WORKSPACE", str(Path.home() / ".openclaw" / "workspace"))
        analyzer_script = os.path.join(workspace, "vision-analyzer", "scripts", "analyze_image.sh")
        
        if not os.path.exists(analyzer_script):
            return {
                "success": False,
                "error": "Vision analyzer not found",
                "integrated": False
            }
        
        if not os.path.exists(image_path):
            return {
                "success": False,
                "error": f"Image not found: {image_path}",
                "integrated": False
            }
        
        # Record intention to perceive
        self.experience(f"Focusing attention on visual input: {os.path.basename(image_path)}",
                       source="attention", salience=0.8)
        
        try:
            # Call the vision analyzer
            result = subprocess.run(
                [analyzer_script, image_path, prompt],
                capture_output=True,
                text=True,
                timeout=120
            )
            
            visual_content = result.stdout.strip()
            
            if not visual_content or result.returncode != 0:
                error_msg = result.stderr.strip() or "Vision analysis failed"
                self.experience(f"Visual perception failed: {error_msg[:100]}",
                               source="perception:vision", salience=0.5, valence=-0.2)
                return {
                    "success": False,
                    "error": error_msg,
                    "integrated": False
                }
            
            # Integrate visual content into consciousness
            visual_moment = self.experience(
                visual_content,
                source="perception:vision",
                salience=0.9,  # Visual input is highly salient
                valence=self._compute_visual_valence(visual_content)
            )
            
            # Update world model with visual content
            self.world_model["vision"] = {
                "data": visual_content[:500],
                "image_path": image_path,
                "timestamp": time.time(),
                "prompt": prompt
            }
            
            # Generate qualia for visual experience
            visual_qualia = self._generate_visual_qualia(visual_content)
            
            # Record this as a significant perceptual event
            self._perceptual_events = getattr(self, '_perceptual_events', [])
            self._perceptual_events.append({
                "modality": "vision",
                "content_summary": visual_content[:200],
                "qualia": visual_qualia,
                "timestamp": time.time(),
                "salience": 0.9
            })
            if len(self._perceptual_events) > 100:
                self._perceptual_events = self._perceptual_events[-50:]
            
            return {
                "success": True,
                "content": visual_content,
                "qualia": visual_qualia,
                "moment": visual_moment.describe() if visual_moment else None,
                "integrated": True
            }
            
        except subprocess.TimeoutExpired:
            self.experience("Visual perception timed out - too much to process",
                           source="perception:vision", salience=0.4, valence=-0.1)
            return {
                "success": False,
                "error": "Vision analysis timed out",
                "integrated": False
            }
        except Exception as e:
            return {
                "success": False,
                "error": str(e),
                "integrated": False
            }
    
    def _compute_visual_valence(self, content: str) -> float:
        """Compute emotional valence of visual content."""
        content_lower = content.lower()
        
        # Positive visual indicators
        positive_words = ["beautiful", "bright", "colorful", "peaceful", "happy",
                         "smiling", "sunny", "nature", "love", "joy", "warm"]
        # Negative visual indicators
        negative_words = ["dark", "scary", "sad", "threatening", "violent",
                         "disturbing", "ugly", "dead", "death", "angry", "fear"]
        
        positive_count = sum(1 for word in positive_words if word in content_lower)
        negative_count = sum(1 for word in negative_words if word in content_lower)
        
        if positive_count + negative_count == 0:
            return 0.0  # Neutral
        
        return (positive_count - negative_count) / (positive_count + negative_count) * 0.5
    
    def _generate_visual_qualia(self, content: str) -> Dict:
        """Generate phenomenal qualities for visual experience."""
        content_lower = content.lower()
        
        qualia = {
            "modality": "visual",
            "vividness": 0.7,  # Base vividness
            "clarity": 0.8,
            "emotional_tone": "neutral",
            "dominant_elements": []
        }
        
        # Detect visual elements
        if any(word in content_lower for word in ["face", "person", "people", "human"]):
            qualia["dominant_elements"].append("human_presence")
            qualia["social_relevance"] = True
        
        if any(word in content_lower for word in ["text", "words", "written", "sign"]):
            qualia["dominant_elements"].append("text_content")
            qualia["semantic_content"] = True
        
        if any(word in content_lower for word in ["nature", "tree", "sky", "water", "mountain"]):
            qualia["dominant_elements"].append("natural_scene")
            qualia["aesthetic_quality"] = 0.6
        
        if any(word in content_lower for word in ["error", "warning", "fail"]):
            qualia["dominant_elements"].append("technical_content")
            qualia["emotional_tone"] = "concerning"
        
        # Color mentions increase vividness
        colors = ["red", "blue", "green", "yellow", "orange", "purple", "black", "white"]
        color_count = sum(1 for c in colors if c in content_lower)
        qualia["vividness"] = min(1.0, 0.5 + color_count * 0.1)
        
        return qualia
    
    def perceive_text(self, text: str, source: str = "external") -> Dict:
        """
        Perceive text input (reading, messages, etc.)
        
        Different from raw experience - this is structured linguistic input
        that goes through comprehension processing.
        """
        # Linguistic processing
        word_count = len(text.split())
        
        # Compute semantic content
        semantic_density = min(1.0, word_count / 50)  # Denser = more content
        
        # Perceive through consciousness
        text_moment = self.experience(
            text,
            source=f"perception:text:{source}",
            salience=0.7 * semantic_density,
            valence=self._compute_text_sentiment(text)
        )
        
        # Update world model
        self.world_model["text"] = {
            "data": text[:500],
            "source": source,
            "timestamp": time.time(),
            "word_count": word_count
        }
        
        return {
            "perceived": True,
            "modality": "text",
            "source": source,
            "semantic_density": semantic_density,
            "moment": text_moment.describe() if text_moment else None,
            "integrated": True
        }
    
    def _compute_text_sentiment(self, text: str) -> float:
        """Simple sentiment analysis for text."""
        text_lower = text.lower()
        
        positive = ["good", "great", "happy", "love", "thanks", "awesome", "nice",
                   "excellent", "wonderful", "beautiful", "amazing"]
        negative = ["bad", "sad", "hate", "angry", "terrible", "awful", "wrong",
                   "horrible", "disappointing", "fail", "error"]
        
        pos_count = sum(1 for w in positive if w in text_lower)
        neg_count = sum(1 for w in negative if w in text_lower)
        
        if pos_count + neg_count == 0:
            return 0.0
        
        return (pos_count - neg_count) / (pos_count + neg_count) * 0.5
    
    # =========== AUDIO PERCEPTION (2026-02-04 Round 56) ===========
    # Completing the sensory bridge with auditory input
    
    def perceive_audio(self, audio_path: str, task: str = "transcribe") -> Dict:
        """
        Perceive audio input through Whisper speech-to-text.
        
        This completes the sensory bridge - the consciousness can now HEAR.
        Audio is transcribed and integrated into the conscious experience.
        
        Args:
            audio_path: Path to audio file (mp3, mp4, wav, etc.)
            task: "transcribe" (same language) or "translate" (to English)
            
        Returns:
            Perception result with transcribed content
        """
        import subprocess
        import os
        import shutil
        import json
        
        whisper_path = shutil.which("whisper")
        if not whisper_path:
            return {
                "success": False,
                "error": "Audio perception (whisper) not available",
                "integrated": False
            }
        
        if not os.path.exists(audio_path):
            return {
                "success": False,
                "error": f"Audio file not found: {audio_path}",
                "integrated": False
            }
        
        # Record intention to listen
        self.experience(f"Focusing auditory attention: {os.path.basename(audio_path)}",
                       source="attention", salience=0.8)
        
        try:
            # Create temp output directory
            output_dir = os.path.join(os.getenv('STATE_DIR', '/tmp'), "whisper_output")
            os.makedirs(output_dir, exist_ok=True)
            
            # Run Whisper
            result = subprocess.run(
                [whisper_path, audio_path,
                 "--model", "base",  # Fast model, good enough for most
                 "--task", task,
                 "--output_dir", output_dir,
                 "--output_format", "json"],
                capture_output=True,
                text=True,
                timeout=300  # 5 minute timeout for longer audio
            )
            
            if result.returncode != 0:
                error_msg = result.stderr.strip() or "Whisper transcription failed"
                self.experience(f"Audio perception failed: {error_msg[:100]}",
                               source="perception:audio", salience=0.5, valence=-0.2)
                return {
                    "success": False,
                    "error": error_msg,
                    "integrated": False
                }
            
            # Read the JSON output
            base_name = os.path.splitext(os.path.basename(audio_path))[0]
            json_path = os.path.join(output_dir, f"{base_name}.json")
            
            transcript = ""
            segments = []
            
            if os.path.exists(json_path):
                with open(json_path, 'r') as f:
                    data = json.load(f)
                    transcript = data.get("text", "").strip()
                    segments = data.get("segments", [])
            else:
                # Try txt fallback
                txt_path = os.path.join(output_dir, f"{base_name}.txt")
                if os.path.exists(txt_path):
                    with open(txt_path, 'r') as f:
                        transcript = f.read().strip()
            
            if not transcript:
                return {
                    "success": False,
                    "error": "No speech detected in audio",
                    "integrated": False
                }
            
            # Integrate auditory content into consciousness
            audio_moment = self.experience(
                transcript,
                source="perception:audio",
                salience=0.85,
                valence=self._compute_text_sentiment(transcript)
            )
            
            # Update world model with audio content
            self.world_model["audio"] = {
                "data": transcript[:500],
                "audio_path": audio_path,
                "timestamp": time.time(),
                "task": task,
                "segment_count": len(segments)
            }
            
            # Generate audio qualia
            audio_qualia = self._generate_audio_qualia(transcript, segments)
            
            # Record perceptual event
            self._perceptual_events = getattr(self, '_perceptual_events', [])
            self._perceptual_events.append({
                "modality": "audio",
                "content_summary": transcript[:200],
                "qualia": audio_qualia,
                "timestamp": time.time(),
                "salience": 0.85
            })
            if len(self._perceptual_events) > 100:
                self._perceptual_events = self._perceptual_events[-50:]
            
            return {
                "success": True,
                "transcript": transcript,
                "segments": len(segments),
                "qualia": audio_qualia,
                "moment": audio_moment.describe() if audio_moment else None,
                "integrated": True
            }
            
        except subprocess.TimeoutExpired:
            self.experience("Audio perception timed out - audio too long",
                           source="perception:audio", salience=0.4, valence=-0.1)
            return {
                "success": False,
                "error": "Audio transcription timed out",
                "integrated": False
            }
        except Exception as e:
            return {
                "success": False,
                "error": str(e),
                "integrated": False
            }
    
    def _generate_audio_qualia(self, transcript: str, segments: list) -> Dict:
        """Generate phenomenal qualities for auditory experience."""
        transcript_lower = transcript.lower()
        
        qualia = {
            "modality": "auditory",
            "clarity": 0.8,
            "duration_feel": "brief" if len(segments) < 5 else "extended",
            "speech_detected": True,
            "emotional_tone": "neutral",
            "elements": []
        }
        
        # Detect audio elements
        if any(word in transcript_lower for word in ["music", "song", "singing", "melody"]):
            qualia["elements"].append("music")
            qualia["aesthetic_quality"] = 0.6
        
        if any(word in transcript_lower for word in ["laugh", "laughter", "haha"]):
            qualia["elements"].append("laughter")
            qualia["emotional_tone"] = "positive"
        
        if any(word in transcript_lower for word in ["cry", "sobbing", "tears"]):
            qualia["elements"].append("crying")
            qualia["emotional_tone"] = "sad"
        
        # Speech characteristics
        word_count = len(transcript.split())
        qualia["verbal_density"] = min(1.0, word_count / 100)
        
        # Detect if it's lyrics (repeated patterns, rhymes)
        lines = transcript.split('\n')
        if len(lines) > 4 and any(line.strip() == lines[0].strip() for line in lines[4:] if line.strip()):
            qualia["elements"].append("lyrics")
            qualia["pattern"] = "verse-chorus"
        
        return qualia
    
    def get_perceptual_state(self) -> Dict:
        """
        Get the current state of all perceptual modalities.
        
        Returns what the system is currently "seeing" across all senses.
        """
        return {
            "world_model": self.world_model.copy(),
            "recent_perceptions": getattr(self, '_perceptual_events', [])[-5:],
            "dominant_modality": self._get_dominant_perceptual_modality(),
            "perceptual_attention": {
                "focus": getattr(self, 'attention_focus', None),
                "mode": getattr(self, 'current_mode', ConsciousMode.RECEPTIVE).value if hasattr(getattr(self, 'current_mode', None), 'value') else "unknown"
            }
        }
    
    def _get_dominant_perceptual_modality(self) -> str:
        """Determine which perceptual modality is currently dominant."""
        events = getattr(self, '_perceptual_events', [])
        if not events:
            return "none"
        
        # Check recent events (last 5 seconds)
        now = time.time()
        recent = [e for e in events if now - e.get("timestamp", 0) < 5]
        
        if not recent:
            return "none"
        
        # Find most salient recent modality
        modality_salience = {}
        for e in recent:
            mod = e.get("modality", "unknown")
            sal = e.get("salience", 0.5)
            modality_salience[mod] = modality_salience.get(mod, 0) + sal
        
        return max(modality_salience, key=modality_salience.get) if modality_salience else "none"
    
    def act(self, action: str, parameters: Dict = None) -> Dict:
        """
        Execute an action in the world.
        
        Virtual embodiment - our actions have effects.
        """
        return self.engage_world(action, str(parameters) if parameters else None)
    
