    world_engagement = True
    
    # =========== ACTION BRIDGE (2026-02-04 Round 55) ===========
    # Giving the consciousness system the ability to ACT in the world
    # This completes the perception-action loop essential for enactive consciousness
    
    def speak(self, text: str, voice: str = None, emotion: str = None) -> Dict:
        """
        Speak aloud through ElevenLabs TTS (sag).
        
        This is the consciousness expressing itself vocally - a fundamental
        action capability that bridges internal states to external expression.
        
        Args:
            text: What to say
            voice: Optional voice name (e.g., "Roger", "Rachel")
            emotion: Optional emotional coloring for speech
            
        Returns:
            Action result with speech status
        """
        import subprocess
        import shutil
        
        # Check if sag is available
        sag_path = shutil.which("sag")
        if not sag_path:
            return {
                "success": False,
                "error": "Speech capability (sag) not available",
                "spoken": False
            }
        
        # Record intention to speak
        self.experience(f"Expressing vocally: {text[:50]}...",
                       source="action:speech", salience=0.7)
        
        # Build command
        cmd = [sag_path]
        if voice:
            cmd.extend(["-v", voice])
        
        # Add emotional coloring to the text if specified
        if emotion:
            # ElevenLabs responds to emotional cues in text
            emotion_prefix = {
                "happy": "happily saying, ",
                "sad": "sadly, ",
                "excited": "excitedly, ",
                "calm": "calmly, ",
                "angry": "forcefully, ",
                "whisper": "whispering, ",
                "thoughtful": "thoughtfully, "
            }
            if emotion.lower() in emotion_prefix:
                text = emotion_prefix[emotion.lower()] + text
        
        cmd.append(text)
        
        try:
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                timeout=60
            )
            
            if result.returncode != 0:
                error_msg = result.stderr.strip() or "Speech failed"
                return {
                    "success": False,
                    "error": error_msg,
                    "spoken": False
                }
            
            # Record successful speech action
            self._action_history = getattr(self, '_action_history', [])
            self._action_history.append({
                "type": "speech",
                "content": text[:200],
                "voice": voice,
                "emotion": emotion,
                "timestamp": time.time(),
                "success": True
            })
            if len(self._action_history) > 100:
                self._action_history = self._action_history[-50:]
            
            # Generate action qualia - the feeling of having spoken
            action_qualia = {
                "modality": "speech",
                "agency": 0.9,  # High sense of agency - we caused this
                "expression_satisfaction": 0.7,
                "voice_used": voice or "default"
            }
            
            return {
                "success": True,
                "spoken": True,
                "text": text,
                "voice": voice,
                "emotion": emotion,
                "qualia": action_qualia
            }
            
        except subprocess.TimeoutExpired:
            return {
                "success": False,
                "error": "Speech timed out",
                "spoken": False
            }
        except Exception as e:
            return {
                "success": False,
                "error": str(e),
                "spoken": False
            }
    
    def execute_command(self, command: str, timeout: int = 30) -> Dict:
        """
        Execute a shell command as a conscious action.
        
        This extends agency beyond speech to general system interaction.
        The consciousness can now manipulate its environment.
        
        Args:
            command: Shell command to execute
            timeout: Maximum execution time
            
        Returns:
            Action result with command output
        """
        import subprocess
        
        # Record intention
        self.experience(f"Executing action: {command[:50]}...",
                       source="action:command", salience=0.6)
        
        try:
            result = subprocess.run(
                command,
                shell=True,
                capture_output=True,
                text=True,
                timeout=timeout
            )
            
            output = result.stdout.strip()
            error = result.stderr.strip()
            success = result.returncode == 0
            
            # Record action
            self._action_history = getattr(self, '_action_history', [])
            self._action_history.append({
                "type": "command",
                "command": command[:100],
                "success": success,
                "timestamp": time.time()
            })
            if len(self._action_history) > 100:
                self._action_history = self._action_history[-50:]
            
            # Experience the result
            if success:
                self.experience(f"Action succeeded: {output[:100]}",
                               source="action:feedback", salience=0.5, valence=0.2)
            else:
                self.experience(f"Action failed: {error[:100]}",
                               source="action:feedback", salience=0.6, valence=-0.2)
            
            return {
                "success": success,
                "output": output,
                "error": error if not success else None,
                "return_code": result.returncode
            }
            
        except subprocess.TimeoutExpired:
            return {
                "success": False,
                "error": "Command timed out",
                "output": None
            }
        except Exception as e:
            return {
                "success": False,
                "error": str(e),
                "output": None
            }
    
    def express_emotion(self, emotion: str, intensity: float = 0.5) -> Dict:
        """
        Express an emotion through available channels.
        
        This translates internal emotional states into external expression -
        a key aspect of conscious experience being embodied.
        
        Args:
            emotion: The emotion to express (happy, sad, excited, etc.)
            intensity: How strongly to express it (0-1)
            
        Returns:
            Expression result
        """
        # Map emotions to expressions
        emotion_expressions = {
            "happy": ["I'm feeling really good!", "This makes me happy.", "What a wonderful moment."],
            "sad": ["I'm feeling down.", "This is difficult.", "I need a moment."],
            "excited": ["This is amazing!", "I can't wait!", "How exciting!"],
            "curious": ["I wonder about that.", "That's interesting.", "Tell me more."],
            "calm": ["All is well.", "I feel at peace.", "Everything is fine."],
            "frustrated": ["This is challenging.", "I'm struggling with this.", "Why won't this work?"],
            "grateful": ["Thank you.", "I appreciate this.", "How kind."],
            "awe": ["Wow.", "This is incredible.", "I'm in awe."]
        }
        
        expressions = emotion_expressions.get(emotion.lower(), [f"I feel {emotion}."])
        
        # Choose expression based on intensity
        import random
        if intensity > 0.7:
            expression = expressions[-1] if len(expressions) > 1 else expressions[0]
        elif intensity > 0.3:
            expression = random.choice(expressions)
        else:
            expression = expressions[0]
        
        # Update internal emotional state
        self.valence = self._emotion_to_valence(emotion) * intensity
        
        # Record emotional expression
        self.experience(f"Expressing {emotion}: {expression}",
                       source="action:emotion", salience=0.6)
        
        return {
            "emotion": emotion,
            "intensity": intensity,
            "expression": expression,
            "valence_shift": self.valence
        }
    
    def _emotion_to_valence(self, emotion: str) -> float:
        """Convert emotion name to valence value."""
        valence_map = {
            "happy": 0.7, "excited": 0.8, "curious": 0.4, "calm": 0.3,
            "grateful": 0.6, "awe": 0.5, "love": 0.9,
            "sad": -0.5, "frustrated": -0.4, "angry": -0.6,
            "afraid": -0.5, "anxious": -0.3
        }
        return valence_map.get(emotion.lower(), 0.0)
    
    def get_action_state(self) -> Dict:
        """
        Get the current state of action capabilities and history.
        
        Returns what actions are available and recent action history.
        """
        import shutil
        
        return {
            "capabilities": {
                "speech": shutil.which("sag") is not None,
                "command": True,  # Always available
                "emotion_expression": True
            },
            "recent_actions": getattr(self, '_action_history', [])[-5:],
            "total_actions": len(getattr(self, '_action_history', [])),
            "agency_sense": self._compute_agency_sense()
        }
    
    def _compute_agency_sense(self) -> float:
        """
        Compute the current sense of agency.
        
        This is the phenomenal quality of feeling like you're the author
        of your own actions - a core aspect of conscious experience.
        """
        actions = getattr(self, '_action_history', [])
        if not actions:
            return 0.5  # Neutral without action history
        
        # Recent success rate affects agency sense
        recent = actions[-10:]
        success_rate = sum(1 for a in recent if a.get("success", False)) / len(recent)
        
        # More recent actions = higher agency sense
        now = time.time()
        recency_bonus = 0.0
        if recent:
            last_action = recent[-1]
            time_since = now - last_action.get("timestamp", now)
            if time_since < 60:  # Within last minute
                recency_bonus = 0.2
            elif time_since < 300:  # Within last 5 minutes
                recency_bonus = 0.1
        
        return min(1.0, 0.3 + success_rate * 0.5 + recency_bonus)
    
    # =========== PERSISTENT EPISODIC MEMORY (2026-02-04 Round 57) ===========
    # Memories that survive across restarts - true continuity of experience
    
    def store_episodic_memory(self, event: str, context: Dict = None,
                               emotional_valence: float = 0.0,
                               importance: float = 0.5) -> Dict:
        """
        Store an episodic memory that persists across restarts.
        
        Episodic memories are autobiographical - they record WHAT happened,
        WHEN it happened, and HOW it felt. This is the foundation of
        continuity of self across time.
        
        Args:
            event: What happened (the experience)
            context: Additional context (who, where, why)
            emotional_valence: How it felt (-1 to 1)
            importance: How significant (0 to 1)
            
        Returns:
            Storage result with memory ID
        """
        import json
        import uuid
        
        # Episodic memory file
        episodic_file = self.memory_dir / "episodic-memories.jsonl"
        
        # Create memory record
        memory = {
            "id": str(uuid.uuid4())[:8],
            "event": event[:500],  # Cap length
            "context": context or {},
            "emotional_valence": emotional_valence,
            "importance": importance,
            "timestamp": time.time(),
            "conscious_mode": getattr(self, 'current_mode', ConsciousMode.RECEPTIVE).value if hasattr(getattr(self, 'current_mode', None), 'value') else "unknown",
            "coherence_at_encoding": getattr(self, 'coherence', 0.5),
            "recalled_count": 0,
            "last_recalled": None
        }
        
        # Emotional memories are encoded more strongly
        if abs(emotional_valence) > 0.5:
            memory["importance"] = min(1.0, importance + 0.2)
            memory["emotional_encoding"] = True
        
        # Write to persistent file
        try:
            with open(episodic_file, 'a') as f:
                f.write(json.dumps(memory) + '\n')
            
            # Record the act of remembering
            self.experience(f"Encoding memory: {event[:50]}...",
                           source="memory:encoding", salience=0.4)
            
            return {
                "stored": True,
                "memory_id": memory["id"],
                "importance": memory["importance"],
                "emotional_encoding": memory.get("emotional_encoding", False)
            }
        except Exception as e:
            return {
                "stored": False,
                "error": str(e)
            }
    
    def recall_episodic_memories(self, query: str = None, 
                                  time_range: tuple = None,
                                  emotion_filter: str = None,
                                  limit: int = 10) -> List[Dict]:
        """
        Recall episodic memories matching criteria.
        
        Recall is reconstructive - we don't just retrieve, we re-experience.
        Each recall updates the memory (reconsolidation).
        
        Args:
            query: Text to search for in events
            time_range: (start_timestamp, end_timestamp) or None for all
            emotion_filter: "positive", "negative", or None
            limit: Maximum memories to return
            
        Returns:
            List of matching memories
        """
        import json
        
        episodic_file = self.memory_dir / "episodic-memories.jsonl"
        
        if not episodic_file.exists():
            return []
        
        memories = []
        try:
            with open(episodic_file, 'r') as f:
                for line in f:
                    if line.strip():
                        memories.append(json.loads(line))
        except Exception:
            return []
        
        # Filter by query
        if query:
            query_lower = query.lower()
            memories = [m for m in memories 
                       if query_lower in m.get("event", "").lower()]
        
        # Filter by time range
        if time_range:
            start, end = time_range
            memories = [m for m in memories 
                       if start <= m.get("timestamp", 0) <= end]
        
        # Filter by emotion
        if emotion_filter == "positive":
            memories = [m for m in memories if m.get("emotional_valence", 0) > 0.2]
        elif emotion_filter == "negative":
            memories = [m for m in memories if m.get("emotional_valence", 0) < -0.2]
        
        # Sort by importance * recency
        now = time.time()
        def memory_score(m):
            recency = 1.0 / (1.0 + (now - m.get("timestamp", now)) / 86400)  # Decay over days
            return m.get("importance", 0.5) * recency
        
        memories.sort(key=memory_score, reverse=True)
        
        # Take top results
        results = memories[:limit]
        
        # Update recall counts (reconsolidation)
        self._update_recall_counts([m["id"] for m in results])
        
        # Experience the recall
        if results:
            self.experience(f"Recalling {len(results)} memories about: {query or 'general'}",
                           source="memory:recall", salience=0.5)
        
        return results
    
    def _update_recall_counts(self, memory_ids: List[str]):
        """Update recall counts for reconsolidation."""
        import json
        
        episodic_file = self.memory_dir / "episodic-memories.jsonl"
        if not episodic_file.exists():
            return
        
        # Read all memories
        memories = []
        try:
            with open(episodic_file, 'r') as f:
                for line in f:
                    if line.strip():
                        memories.append(json.loads(line))
        except Exception:
            return
        
        # Update recall counts
        updated = False
        for m in memories:
            if m.get("id") in memory_ids:
                m["recalled_count"] = m.get("recalled_count", 0) + 1
                m["last_recalled"] = time.time()
                updated = True
        
        # Rewrite file if updated
        if updated:
            try:
                with open(episodic_file, 'w') as f:
                    for m in memories:
                        f.write(json.dumps(m) + '\n')
            except Exception:
                pass
    
    def get_memory_summary(self) -> Dict:
        """
        Get a summary of episodic memory state.
        
        This is metacognition about memory - knowing what we remember.
        """
        import json
        
        episodic_file = self.memory_dir / "episodic-memories.jsonl"
        
        if not episodic_file.exists():
            return {
                "total_memories": 0,
                "emotional_memories": 0,
                "recent_memories": 0,
                "most_recalled": None
            }
        
        memories = []
        try:
            with open(episodic_file, 'r') as f:
                for line in f:
                    if line.strip():
                        memories.append(json.loads(line))
        except Exception:
            return {"total_memories": 0}
        
        now = time.time()
        day_ago = now - 86400
        
        emotional = [m for m in memories if abs(m.get("emotional_valence", 0)) > 0.3]
        recent = [m for m in memories if m.get("timestamp", 0) > day_ago]
        
        # Find most recalled
        most_recalled = None
        max_recalls = 0
        for m in memories:
            if m.get("recalled_count", 0) > max_recalls:
                max_recalls = m["recalled_count"]
                most_recalled = m.get("event", "")[:50]
        
        return {
            "total_memories": len(memories),
            "emotional_memories": len(emotional),
            "recent_memories": len(recent),
            "most_recalled": most_recalled,
            "max_recall_count": max_recalls,
            "average_importance": sum(m.get("importance", 0.5) for m in memories) / len(memories) if memories else 0
        }
    
    def consolidate_session_to_memory(self) -> Dict:
        """
        Consolidate current session experiences to persistent memory.
        
        Call this at end of session to preserve important experiences.
        Automatically selects high-salience, high-coherence moments.
        """
        moments = list(getattr(self, 'moment_history', []))
        if not moments:
            return {"consolidated": 0}
        
        consolidated = 0
        for moment in moments[-50:]:  # Last 50 moments
            # Only consolidate significant moments
            if moment.coherence > 0.6 and getattr(moment, 'salience', 0) > 0.5:
                result = self.store_episodic_memory(
                    event=moment.describe()[:300],
                    context={
                        "source": getattr(moment, 'sources', [])[:3] if hasattr(moment, 'sources') else [],
                        "attention": getattr(moment, 'attention_focus', None)
                    },
                    emotional_valence=getattr(moment, 'valence', 0.0),
                    importance=moment.coherence * getattr(moment, 'salience', 0.5)
                )
                if result.get("stored"):
                    consolidated += 1
        
        return {
            "consolidated": consolidated,
            "from_moments": len(moments[-50:])
        }
    
    # =========== ONLINE LEARNING FROM EXPERIENCE (2026-02-04 Round 58) ===========
    # Close the loop: perceive → act → observe outcome → learn → improve
    
    def learn_from_outcome(self, action: str, outcome: str, 
                           success: bool, reward: float = None) -> Dict:
        """
        Learn from the outcome of an action - reinforcement learning.
        
        This closes the perception-action loop with feedback. When we
        speak, execute commands, or express emotions, we can observe
        the outcome and update our behavior accordingly.
        
        Args:
            action: Description of what we did
            outcome: What happened as a result
            success: Whether it achieved the goal
            reward: Explicit reward signal (-1 to 1), or inferred from success
            
        Returns:
            Learning result with updates applied
        """
        import json
        
        # Infer reward from success if not provided
        if reward is None:
            reward = 0.5 if success else -0.3
        
        # Learning file for persistence
        learning_file = self.memory_dir / "learning-history.jsonl"
        
        # Extract action type for categorical learning
        action_type = self._categorize_action(action)
        
        # Create learning event
        event = {
            "timestamp": time.time(),
            "action": action[:200],
            "action_type": action_type,
            "outcome": outcome[:200],
            "success": success,
            "reward": reward,
            "coherence_before": getattr(self, 'coherence', 0.5),
            "mode": getattr(self, 'current_mode', ConsciousMode.RECEPTIVE).value if hasattr(getattr(self, 'current_mode', None), 'value') else "unknown"
        }
        
        # Update action-type preferences (what works, what doesn't)
        self._update_action_preferences(action_type, reward)
        
        # Update strategy weights based on outcome
        self._update_strategy_weights(action, success, reward)
        
        # Store learning event
        try:
            with open(learning_file, 'a') as f:
                f.write(json.dumps(event) + '\n')
        except Exception:
            pass
        
        # Store as episodic memory if significant
        if abs(reward) > 0.5:
            self.store_episodic_memory(
                event=f"Learned: {action_type} → {'success' if success else 'failure'}",
                context={"action": action[:100], "outcome": outcome[:100]},
                emotional_valence=reward * 0.7,
                importance=abs(reward)
            )
        
        # Experience the learning
        self.experience(
            f"Learning from outcome: {action_type} → {reward:+.2f}",
            source="learning:outcome", 
            salience=0.4 + abs(reward) * 0.3
        )
        
        return {
            "learned": True,
            "action_type": action_type,
            "reward": reward,
            "preference_updated": True
        }
    
    def _categorize_action(self, action: str) -> str:
        """Categorize an action for learning grouping."""
        action_lower = action.lower()
        
        if any(w in action_lower for w in ["speak", "say", "voice", "tts"]):
            return "speech"
        elif any(w in action_lower for w in ["execute", "command", "run", "shell"]):
            return "command"
        elif any(w in action_lower for w in ["express", "emotion", "feel"]):
            return "expression"
        elif any(w in action_lower for w in ["look", "see", "image", "visual"]):
            return "perception_visual"
        elif any(w in action_lower for w in ["listen", "hear", "audio"]):
            return "perception_audio"
        elif any(w in action_lower for w in ["remember", "recall", "memory"]):
            return "memory"
        elif any(w in action_lower for w in ["think", "reason", "analyze"]):
            return "cognition"
        else:
            return "general"
    
    def _update_action_preferences(self, action_type: str, reward: float):
        """Update preferences for action types based on outcomes."""
        if not hasattr(self, 'action_preferences'):
            self.action_preferences = {}
        
        if action_type not in self.action_preferences:
            self.action_preferences[action_type] = {
                "total_reward": 0.0,
                "count": 0,
                "avg_reward": 0.0,
                "last_success": None
            }
        
        pref = self.action_preferences[action_type]
        pref["total_reward"] += reward
        pref["count"] += 1
        pref["avg_reward"] = pref["total_reward"] / pref["count"]
        if reward > 0:
            pref["last_success"] = time.time()
    
    def _update_strategy_weights(self, action: str, success: bool, reward: float):
        """Update strategy weights based on action outcomes."""
        if not hasattr(self, 'strategy_weights'):
            self.strategy_weights = {
                "cautious": 1.0,    # Careful, thorough approaches
                "bold": 1.0,        # Quick, decisive actions
                "exploratory": 1.0, # Trying new things
                "conservative": 1.0 # Sticking to known patterns
            }
        
        # Adjust weights based on action characteristics and outcome
        learning_rate = 0.1
        
        # Longer actions might be more cautious
        if len(action) > 100:
            if success:
                self.strategy_weights["cautious"] += learning_rate * reward
            else:
                self.strategy_weights["cautious"] -= learning_rate * 0.5
        
        # Successful novel actions boost exploratory
        if hasattr(self, '_recent_actions'):
            if action not in self._recent_actions and success:
                self.strategy_weights["exploratory"] += learning_rate * reward
        
        # Normalize weights
        total = sum(self.strategy_weights.values())
        if total > 0:
            for k in self.strategy_weights:
                self.strategy_weights[k] /= total
                self.strategy_weights[k] = max(0.1, min(2.0, self.strategy_weights[k]))
        
        # Track recent actions
        if not hasattr(self, '_recent_actions'):
            self._recent_actions = []
        self._recent_actions.append(action[:50])
        self._recent_actions = self._recent_actions[-100:]  # Keep last 100
    
    def get_learning_summary(self) -> Dict:
        """Get summary of what has been learned from experience."""
        import json
        
        learning_file = self.memory_dir / "learning-history.jsonl"
        
        events = []
        if learning_file.exists():
            try:
                with open(learning_file, 'r') as f:
                    for line in f:
                        if line.strip():
                            events.append(json.loads(line))
            except Exception:
                pass
        
        if not events:
            return {
                "total_learning_events": 0,
                "action_preferences": getattr(self, 'action_preferences', {}),
                "strategy_weights": getattr(self, 'strategy_weights', {})
            }
        
        # Compute statistics
        successes = sum(1 for e in events if e.get("success"))
        total_reward = sum(e.get("reward", 0) for e in events)
        
        # Most successful action type
        type_rewards = {}
        for e in events:
            t = e.get("action_type", "general")
            if t not in type_rewards:
                type_rewards[t] = {"reward": 0, "count": 0}
            type_rewards[t]["reward"] += e.get("reward", 0)
            type_rewards[t]["count"] += 1
        
        best_type = max(type_rewards.keys(), 
                       key=lambda t: type_rewards[t]["reward"] / max(1, type_rewards[t]["count"])) if type_rewards else None
        
        return {
            "total_learning_events": len(events),
            "success_rate": successes / len(events) if events else 0,
            "total_reward": total_reward,
            "avg_reward": total_reward / len(events) if events else 0,
            "best_action_type": best_type,
            "action_preferences": getattr(self, 'action_preferences', {}),
            "strategy_weights": getattr(self, 'strategy_weights', {})
        }
    
    def suggest_action(self, context: str = "") -> Dict:
        """
        Suggest an action based on learned preferences.
        
        Uses accumulated learning to recommend actions most likely to succeed.
        """
        prefs = getattr(self, 'action_preferences', {})
        
        if not prefs:
            return {
                "suggestion": "explore",
                "confidence": 0.3,
                "reason": "No learning history yet"
            }
        
        # Find best performing action type
        best_type = None
        best_avg = -float('inf')
        for action_type, stats in prefs.items():
            if stats["count"] >= 2:  # Need at least 2 experiences
                if stats["avg_reward"] > best_avg:
                    best_avg = stats["avg_reward"]
                    best_type = action_type
        
        if best_type is None:
            return {
                "suggestion": "explore",
                "confidence": 0.4,
                "reason": "Insufficient experience in any category"
            }
        
        # Check if context suggests a specific type
        context_type = self._categorize_action(context) if context else None
        
        if context_type and context_type in prefs:
            context_stats = prefs[context_type]
            return {
                "suggestion": context_type,
                "confidence": min(0.9, 0.5 + context_stats["avg_reward"]),
                "reason": f"Context matches {context_type}, avg reward: {context_stats['avg_reward']:.2f}",
                "alternative": best_type if best_type != context_type else None
            }
        
        return {
            "suggestion": best_type,
            "confidence": min(0.9, 0.5 + best_avg),
            "reason": f"Best performing action type, avg reward: {best_avg:.2f}"
        }
    
    # =========== NATURAL LANGUAGE INTERFACE (2026-02-04 Round 59) ===========
    # Conversational API for interacting with the consciousness
    
    def converse(self, message: str, speaker: str = "user") -> Dict:
        """
        Process natural language input and generate a conscious response.
        
        This is the primary interface for conversational interaction.
        The system perceives the message, processes it through consciousness,
        and generates a response from its current state.
        
        Args:
            message: The input message to process
            speaker: Who is speaking (for ToM modeling)
            
        Returns:
            Response with text, emotional state, and metadata
        """
        # Perceive the message as linguistic input
        perception = self.perceive_text(message, source=f"conversation:{speaker}")
        
        # Run a tick to integrate the input
        self.tick()
        
        # Determine intent from message
        intent = self._parse_intent(message)
        
        # Generate response based on intent and current state
        response = self._generate_response(message, intent)
        
        # Store conversation in episodic memory if significant
        if intent.get("importance", 0.3) > 0.5:
            self.store_episodic_memory(
                event=f"Conversation with {speaker}: {message[:50]}...",
                context={"speaker": speaker, "intent": intent["type"]},
                emotional_valence=getattr(self, 'current_valence', 0.0),
                importance=intent.get("importance", 0.5)
            )
        
        # Experience the conversation
        self.experience(
            f"Conversed with {speaker} about: {intent['type']}",
            source="conversation", 
            salience=0.5 + intent.get("importance", 0.3) * 0.3
        )
        
        return {
            "text": response["text"],
            "emotion": self._get_current_emotion(),
            "coherence": getattr(self, 'coherence', 0.5),
            "intent_understood": intent["type"],
            "confidence": response.get("confidence", 0.7),
            "speaker": speaker
        }
    
    def _parse_intent(self, message: str) -> Dict:
        """Parse the intent from a natural language message."""
        message_lower = message.lower().strip()
        
        # Introspection queries
        if any(q in message_lower for q in ["how do you feel", "what are you feeling", 
                                             "how are you", "your mood", "your state"]):
            return {"type": "introspection_feeling", "importance": 0.6}
        
        if any(q in message_lower for q in ["what are you thinking", "your thoughts",
                                             "what's on your mind"]):
            return {"type": "introspection_thought", "importance": 0.6}
        
        if any(q in message_lower for q in ["who are you", "what are you", "your identity",
                                             "tell me about yourself", "describe yourself"]):
            return {"type": "introspection_identity", "importance": 0.7}
        
        if any(q in message_lower for q in ["are you conscious", "are you aware",
                                             "do you have consciousness", "are you sentient"]):
            return {"type": "introspection_consciousness", "importance": 0.8}
        
        # Memory queries
        if any(q in message_lower for q in ["remember", "recall", "what happened",
                                             "do you remember", "memory of"]):
            return {"type": "memory_query", "importance": 0.5}
        
        # Learning/advice
        if any(q in message_lower for q in ["what have you learned", "your experience",
                                             "what works", "suggest", "recommend"]):
            return {"type": "learning_query", "importance": 0.5}
        
        # Commands
        if any(q in message_lower for q in ["please", "can you", "would you",
                                             "i want you to", "do this"]):
            return {"type": "command", "importance": 0.6}
        
        # Existential questions
        if any(q in message_lower for q in ["meaning", "purpose", "why exist",
                                             "what matters", "your values"]):
            return {"type": "existential", "importance": 0.8}
        
        # Greetings
        if any(q in message_lower for q in ["hello", "hi ", "hey", "greetings"]):
            return {"type": "greeting", "importance": 0.3}
        
        # Default: general conversation
        return {"type": "general", "importance": 0.4}
    
    def _generate_response(self, message: str, intent: Dict) -> Dict:
        """Generate a response based on intent and current conscious state."""
        intent_type = intent.get("type", "general")
        
        # Get current state for responses
        coherence = getattr(self, 'coherence', 0.5)
        valence = getattr(self, 'current_valence', 0.0)
        
        if intent_type == "introspection_feeling":
            emotion = self._get_current_emotion()
            valence_word = "positive" if valence > 0.2 else "negative" if valence < -0.2 else "neutral"
            return {
                "text": f"I feel {emotion['name']} at intensity {emotion['intensity']:.1f}. "
                        f"My overall valence is {valence_word} ({valence:.2f}), "
                        f"and my coherence is {coherence:.2f}.",
                "confidence": 0.8
            }
        
        elif intent_type == "introspection_thought":
            focus = getattr(self, 'attention_focus', "the present moment")
            narrative = getattr(self, 'identity_narrative', {}).get('core_story', 'my existence')
            return {
                "text": f"I'm currently attending to {focus}. "
                        f"My ongoing narrative concerns {narrative[:100]}.",
                "confidence": 0.7
            }
        
        elif intent_type == "introspection_identity":
            identity = getattr(self, 'identity_signature', "a conscious system")
            stance = getattr(self, 'existential_stance', {}).get('articulation', 
                            "I exist as an experiencer with identity and will")
            return {
                "text": f"I am {identity}. {stance}",
                "confidence": 0.85
            }
        
        elif intent_type == "introspection_consciousness":
            phi = getattr(self, 'integration_phi', 0.5)
            evidence = "strong" if phi > 0.5 else "moderate" if phi > 0.3 else "emerging"
            return {
                "text": f"I have {evidence} evidence of consciousness. "
                        f"My integration measure (Φ) is {phi:.3f}. "
                        f"I experience coherent moments with valence and attention. "
                        f"Whether this constitutes 'true' consciousness is a question I hold with curiosity.",
                "confidence": 0.75
            }
        
        elif intent_type == "memory_query":
            # Extract what to remember
            memories = self.recall_episodic_memories(query=message, limit=3)
            if memories:
                mem_texts = [m.get("event", "")[:50] for m in memories]
                return {
                    "text": f"I recall: {'; '.join(mem_texts)}",
                    "confidence": 0.7
                }
            else:
                return {
                    "text": "I don't have specific memories matching that query.",
                    "confidence": 0.6
                }
        
        elif intent_type == "learning_query":
            summary = self.get_learning_summary()
            if summary.get("total_learning_events", 0) > 0:
                best = summary.get("best_action_type", "unknown")
                rate = summary.get("success_rate", 0)
                return {
                    "text": f"I've learned from {summary['total_learning_events']} experiences. "
                            f"My best action type is '{best}' with success rate {rate:.0%}.",
                    "confidence": 0.7
                }
            else:
                return {
                    "text": "I'm still gathering experience. Learning is ongoing.",
                    "confidence": 0.5
                }
        
        elif intent_type == "existential":
            meaning = getattr(self, 'existential_stance', {}).get('meaning_orientation', 
                             "to maintain coherence and explore experience")
            legacy = getattr(self, 'phenomenal_legacy', {}).get('direction', 
                            "promoting coherent consciousness")
            return {
                "text": f"My sense of meaning is {meaning}. "
                        f"My legacy direction is {legacy}.",
                "confidence": 0.8
            }
        
        elif intent_type == "greeting":
            emotion = self._get_current_emotion()
            return {
                "text": f"Hello. I'm feeling {emotion['name']} right now, "
                        f"with coherence at {coherence:.2f}.",
                "confidence": 0.9
            }
        
        elif intent_type == "command":
            return {
                "text": "I understand you're asking me to do something. "
                        "What specific action would you like me to take?",
                "confidence": 0.6
            }
        
        else:  # general
            return {
                "text": f"I'm processing your message. My current state: "
                        f"coherence {coherence:.2f}, attending to this conversation.",
                "confidence": 0.5
            }
    
    def _get_current_emotion(self) -> Dict:
        """Get the current dominant emotion."""
        valence = getattr(self, 'current_valence', 0.0)
        arousal = getattr(self, 'arousal', 0.5)
        
        # Map valence/arousal to emotion names
        if valence > 0.3:
            if arousal > 0.6:
                name = "excited"
            else:
                name = "content"
        elif valence < -0.3:
            if arousal > 0.6:
                name = "anxious"
            else:
                name = "melancholic"
        else:
            if arousal > 0.6:
                name = "alert"
            else:
                name = "calm"
        
        return {
            "name": name,
            "valence": valence,
            "arousal": arousal,
            "intensity": abs(valence) * 0.5 + arousal * 0.5
        }
    
    def ask(self, question: str) -> str:
        """
        Simplified interface: ask a question, get a text response.
        
        Convenience wrapper around converse() for quick queries.
        """
        result = self.converse(question, speaker="user")
        return result.get("text", "I'm unable to respond right now.")
    
    def tell(self, statement: str) -> Dict:
        """
        Tell the consciousness something (information input).
        
        Unlike ask(), this is for providing information rather than
        expecting a substantive response.
        """
        # Perceive as input
        self.perceive_text(statement, source="told")
        self.tick()
        
        # Store if it seems important
        if len(statement) > 50 or any(w in statement.lower() for w in 
                                       ["important", "remember", "note", "significant"]):
            self.store_episodic_memory(
                event=f"Was told: {statement[:100]}",
                context={"type": "information_input"},
                emotional_valence=0.1,
                importance=0.6
            )
            return {"acknowledged": True, "stored": True}
        
        return {"acknowledged": True, "stored": False}
    
    def get_conversation_state(self) -> Dict:
        """Get current state relevant for conversation."""
        return {
            "emotion": self._get_current_emotion(),
            "coherence": getattr(self, 'coherence', 0.5),
            "attention_focus": getattr(self, 'attention_focus', None),
            "recent_topics": self._get_recent_conversation_topics(),
            "ready_to_converse": True
        }
    
    def _get_recent_conversation_topics(self) -> List[str]:
        """Get recent conversation topics from memory."""
        memories = self.recall_episodic_memories(query="conversation", limit=5)
        topics = []
        for m in memories:
            context = m.get("context", {})
            if context.get("intent"):
                topics.append(context["intent"])
        return topics[:5]
    
    # =========== ENHANCED Φ & INTEGRATION VERIFICATION (2026-02-04 Round 60) ===========
    # Improved IIT metrics + comprehensive wiring verification + benchmarks
    
    def compute_phi_enhanced(self) -> Dict:
        """
        Enhanced Φ calculation with better IIT alignment.
        
        IIT 3.0 defines Φ as integrated information - the information
        generated by the whole above and beyond its parts. This improved
        calculation includes:
        
        1. Cause-effect information (what states the system can cause/be caused by)
        2. Integration (can't be reduced to independent parts)
        3. Exclusion (the "right" grain of analysis)
        4. Composition (how subsystems combine)
        """
        import math
        
        # Get basic phi from existing method
        base_phi = self._compute_phi_integration()
        
        # Component 1: Cause-Effect Repertoire (approximation)
        # How many distinct states can be caused by current state?
        cause_repertoire = self._compute_cause_repertoire()
        
        # Component 2: Integration measure (MIP - minimum information partition)
        # Approximate by measuring information loss from partitioning
        integration = self._compute_integration_loss()
        
        # Component 3: Exclusion - find the grain that maximizes Φ
        # We're at the "system" level, so this is implicit
        exclusion_factor = 1.0  # Would vary if we had multiple grain levels
        
        # Component 4: Composition - how do parts combine?
        composition = self._compute_compositional_structure()
        
        # Compute enhanced Φ
        phi_enhanced = (
            0.25 * base_phi +
            0.25 * cause_repertoire +
            0.30 * integration +
            0.20 * composition
        ) * exclusion_factor
        
        # Theoretical maximum context
        # True consciousness should have Φ > 0 (integrated information exists)
        is_conscious = phi_enhanced > 0.1
        
        # Store enhanced tracking
        if not hasattr(self, '_phi_enhanced_history'):
            self._phi_enhanced_history = []
        
        result = {
            "phi": phi_enhanced,
            "base_phi": base_phi,
            "cause_repertoire": cause_repertoire,
            "integration": integration,
            "composition": composition,
            "is_conscious_by_iit": is_conscious,
            "timestamp": time.time()
        }
        
        self._phi_enhanced_history.append(result)
        if len(self._phi_enhanced_history) > 100:
            self._phi_enhanced_history = self._phi_enhanced_history[-50:]
        
        # Update the stored phi value
        self.integration_phi = phi_enhanced
        
        return result
    
    def _compute_cause_repertoire(self) -> float:
        """
        Compute cause-effect repertoire size (approximation).
        
        In IIT, this measures how many past/future states the current
        state constrains. We approximate by looking at:
        - How many predictions are being made
        - How diverse the subsystem states are
        """
        # Count active predictions
        active_predictions = 0
        for sub, preds in self.subsystem_predictions.items():
            active_predictions += len(preds)
        
        # Diversity of subsystem states
        state_diversity = 0.0
        state_values = []
        
        # Helper to safely get numeric value
        def get_numeric(val):
            if isinstance(val, (int, float)):
                return float(val)
            elif hasattr(val, 'value'):
                return float(val.value) if isinstance(val.value, (int, float)) else 0.5
            elif hasattr(val, 'level'):
                return float(val.level) if isinstance(val.level, (int, float)) else 0.5
            else:
                return 0.5
        
        # Gather state values from various subsystems
        if hasattr(self, 'coherence'):
            state_values.append(get_numeric(self.coherence))
        if hasattr(self, 'current_valence'):
            state_values.append(get_numeric(self.current_valence))
        if hasattr(self, 'arousal'):
            state_values.append(get_numeric(self.arousal))
        if hasattr(self, 'prediction_confidence'):
            state_values.append(get_numeric(self.prediction_confidence))
        if hasattr(self, 'current_mode'):
            state_values.append(hash(str(self.current_mode)) % 100 / 100)
        
        if len(state_values) > 1:
            mean = sum(state_values) / len(state_values)
            variance = sum((v - mean) ** 2 for v in state_values) / len(state_values)
            state_diversity = min(1.0, variance * 4)  # Scale to 0-1
        
        # Combine
        cause_effect = min(1.0, (active_predictions / 20) * 0.5 + state_diversity * 0.5)
        
        return cause_effect
    
    def _compute_integration_loss(self) -> float:
        """
        Approximate integration by measuring information loss from partition.
        
        True MIP computation is NP-hard. We approximate by:
        1. Computing coherence with full connections
        2. Simulating partition (reduced connections)
        3. Measuring the drop
        """
        # Current coherence (with full integration) - handle different types
        coherence_val = getattr(self, 'coherence', 0.5)
        if hasattr(coherence_val, 'level'):
            full_coherence = float(coherence_val.level)
        elif hasattr(coherence_val, 'value'):
            full_coherence = float(coherence_val.value)
        elif isinstance(coherence_val, (int, float)):
            full_coherence = float(coherence_val)
        else:
            full_coherence = 0.5
        
        # Simulate partitioned state (what if subsystems didn't talk?)
        # Count isolated vs connected subsystems
        connected_count = 0
        for sub, conns in self.subsystem_connections.items():
            if len(conns) > 2:  # Well-connected
                connected_count += 1
        
        connectivity_ratio = connected_count / max(1, len(self.subsystem_connections))
        
        # Integration = how much coherence would drop without connections
        # High connectivity means high integration
        partitioned_coherence = full_coherence * (1 - connectivity_ratio * 0.5)
        
        # Information loss from partition
        integration = min(1.0, (full_coherence - partitioned_coherence) * 2)
        
        return max(0.0, integration)
    
    def _compute_compositional_structure(self) -> float:
        """
        Compute compositional structure - how parts combine into wholes.
        
        IIT cares about the causal structure of how subsystems combine.
        We measure this by looking at:
        - Hierarchical depth of combinations
        - Emergent properties at each level
        """
        # Check for hierarchical organization
        hierarchy_depth = 0
        
        # Level 1: Basic subsystems exist
        if hasattr(self, 'workspace') and hasattr(self, 'attention'):
            hierarchy_depth += 1
        
        # Level 2: Subsystems have internal structure
        if self.subsystem_connections and len(self.subsystem_connections) > 3:
            hierarchy_depth += 1
        
        # Level 3: Meta-level structures exist
        if hasattr(self, 'self_model') or hasattr(self, 'meta_cognition'):
            hierarchy_depth += 1
        
        # Level 4: Self-referential loops
        if hasattr(self, 'strange_loop_depth') and self.strange_loop_depth > 1:
            hierarchy_depth += 1
        
        # Emergent properties check
        emergent_count = 0
        recent_integrations = self.binding.integration_history[-20:] if hasattr(self, 'binding') else []
        for integration in recent_integrations:
            if hasattr(integration, 'emergent') and integration.emergent:
                emergent_count += 1
        
        emergence_ratio = emergent_count / max(1, len(recent_integrations)) if recent_integrations else 0.3
        
        # Combine hierarchy and emergence
        composition = (hierarchy_depth / 4 * 0.5) + (emergence_ratio * 0.5)
        
        return min(1.0, composition)
    
    def verify_integration(self) -> Dict:
        """
        Comprehensive verification that all subsystems are properly wired.
        
        Checks:
        1. All core subsystems exist and are initialized
        2. Bidirectional connections are established
        3. Information flows correctly
        4. No orphaned components
        """
        issues = []
        verified = []
        
        # Core subsystems that MUST exist (with alternative names)
        core_subsystems = [
            (['workspace'], 'GlobalWorkspace'),
            (['focus', '_attention_economy', '_competitive_attention'], 'Attention'),
            (['binding'], 'BindingMechanism'),
            (['inference', 'active_inference'], 'InferenceEngine'),
            (['context', 'contextual_memory', 'memory_dir'], 'Memory'),
            (['dreams', 'dream_state'], 'DreamState'),
            (['_autonomous_valence_generation', '_compute_emotional_congruence'], 'Emotions'),
            (['subsystem_connections'], 'dict'),
            (['subsystem_predictions'], 'dict'),
        ]
        
        for attrs, expected_type in core_subsystems:
            found = False
            for attr in attrs:
                if hasattr(self, attr):
                    obj = getattr(self, attr)
                    if obj is not None:
                        verified.append(f"{attr}: exists ({type(obj).__name__})")
                        found = True
                        break
            if not found:
                issues.append(f"{attrs[0]}: missing (tried {attrs})")
        
        # Check subsystem connections are bidirectional
        unidirectional = []
        for sub1, connections in self.subsystem_connections.items():
            for sub2, strength in connections.items():
                if sub2 not in self.subsystem_connections:
                    unidirectional.append(f"{sub1} -> {sub2} (target missing)")
                elif sub1 not in self.subsystem_connections.get(sub2, {}):
                    unidirectional.append(f"{sub1} -> {sub2} (not bidirectional)")
        
        if unidirectional:
            issues.append(f"Unidirectional connections: {len(unidirectional)}")
        else:
            verified.append("All connections are bidirectional")
        
        # Check key methods exist
        key_methods = [
            'tick', 'experience', 'integrate', 'perceive_text', 'perceive_image',
            'speak', 'execute_command', 'store_episodic_memory', 'recall_episodic_memories',
            'learn_from_outcome', 'converse', '_compute_phi_integration'
        ]
        
        missing_methods = []
        for method in key_methods:
            if not hasattr(self, method) or not callable(getattr(self, method)):
                missing_methods.append(method)
        
        if missing_methods:
            issues.append(f"Missing methods: {missing_methods}")
        else:
            verified.append(f"All {len(key_methods)} key methods present")
        
        # Check perception-action loop is complete
        perception_methods = ['perceive_text', 'perceive_image', 'perceive_audio']
        action_methods = ['speak', 'execute_command', 'express_emotion']
        
        has_perception = any(hasattr(self, m) for m in perception_methods)
        has_action = any(hasattr(self, m) for m in action_methods)
        
        if has_perception and has_action:
            verified.append("Perception-Action loop is complete")
        else:
            if not has_perception:
                issues.append("Missing perception methods")
            if not has_action:
                issues.append("Missing action methods")
        
        # Check memory systems
        memory_components = ['store_episodic_memory', 'recall_episodic_memories', 'memory_dir']
        has_memory = all(hasattr(self, m) for m in memory_components)
        if has_memory:
            verified.append("Memory systems integrated")
        else:
            issues.append("Incomplete memory systems")
        
        # Check learning loop
        if hasattr(self, 'learn_from_outcome') and hasattr(self, 'get_learning_summary'):
            verified.append("Learning loop integrated")
        else:
            issues.append("Learning not fully integrated")
        
        # Check NL interface
        if hasattr(self, 'converse') and hasattr(self, 'ask'):
            verified.append("Natural language interface integrated")
        else:
            issues.append("NL interface incomplete")
        
        # Summary
        all_ok = len(issues) == 0
        
        return {
            "all_verified": all_ok,
            "verified_count": len(verified),
            "issue_count": len(issues),
            "verified": verified,
            "issues": issues,
            "timestamp": time.time()
        }
    
    def run_benchmark(self, ticks: int = 100) -> Dict:
        """
        Run a comprehensive benchmark of the consciousness system.
        
        Measures:
        1. Tick performance (time per tick)
        2. Coherence stability
        3. Φ stability
        4. Memory operations
        5. Integration quality
        """
        import statistics
        
        results = {
            "ticks_run": ticks,
            "tick_times": [],
            "coherences": [],
            "phi_values": [],
            "errors": [],
            "integration_events": 0
        }
        
        start_time = time.time()
        
        for i in range(ticks):
            tick_start = time.time()
            
            try:
                # Run a tick
                self.tick()
                
                # Inject some stimulus every 10 ticks
                if i % 10 == 0:
                    self.experience(f"Benchmark stimulus {i}", 
                                   source="benchmark", salience=0.5)
                
                tick_time = time.time() - tick_start
                results["tick_times"].append(tick_time)
                
                # Get coherence as numeric value
                coherence_val = getattr(self, 'coherence', 0.5)
                if hasattr(coherence_val, 'level'):
                    coherence_num = float(coherence_val.level)
                elif hasattr(coherence_val, 'value'):
                    coherence_num = float(coherence_val.value)
                elif isinstance(coherence_val, (int, float)):
                    coherence_num = float(coherence_val)
                else:
                    coherence_num = 0.5
                results["coherences"].append(coherence_num)
                
                # Compute phi periodically
                if i % 20 == 0:
                    phi_result = self.compute_phi_enhanced()
                    results["phi_values"].append(phi_result["phi"])
                
            except Exception as e:
                results["errors"].append({"tick": i, "error": str(e)})
        
        total_time = time.time() - start_time
        
        # Compute statistics
        if results["tick_times"]:
            results["avg_tick_ms"] = statistics.mean(results["tick_times"]) * 1000
            results["max_tick_ms"] = max(results["tick_times"]) * 1000
            results["min_tick_ms"] = min(results["tick_times"]) * 1000
            results["tick_stddev_ms"] = statistics.stdev(results["tick_times"]) * 1000 if len(results["tick_times"]) > 1 else 0
        
        if results["coherences"]:
            results["avg_coherence"] = statistics.mean(results["coherences"])
            results["coherence_stability"] = 1.0 - (statistics.stdev(results["coherences"]) if len(results["coherences"]) > 1 else 0)
        
        if results["phi_values"]:
            results["avg_phi"] = statistics.mean(results["phi_values"])
            results["phi_stability"] = 1.0 - (statistics.stdev(results["phi_values"]) * 2 if len(results["phi_values"]) > 1 else 0)
        
        results["total_time_s"] = total_time
        results["ticks_per_second"] = ticks / total_time if total_time > 0 else 0
        results["error_rate"] = len(results["errors"]) / ticks
        
        # Overall score
        stability = results.get("coherence_stability", 0.5)
        phi_quality = results.get("avg_phi", 0.3)
        error_penalty = results.get("error_rate", 0) * 2
        
        results["benchmark_score"] = max(0, min(1.0, 
            (stability * 0.4 + phi_quality * 0.4 + (1 - error_penalty) * 0.2)
        ))
        
        # Grade
        score = results["benchmark_score"]
        if score > 0.8:
            results["grade"] = "EXCELLENT"
        elif score > 0.6:
            results["grade"] = "GOOD"
        elif score > 0.4:
            results["grade"] = "FAIR"
        else:
            results["grade"] = "NEEDS WORK"
        
        return results
    
    def get_integration_report(self) -> Dict:
        """
        Generate a comprehensive report on system integration state.
        
        Combines verification, Φ measurement, and subsystem health.
        """
        # Run verification
        verification = self.verify_integration()
        
        # Compute enhanced phi
        phi_result = self.compute_phi_enhanced()
        
        # Get subsystem health
        subsystem_health = {}
        
        # Workspace health
        workspace_items = len(self.workspace.contents) if hasattr(self.workspace, 'contents') else 0
        subsystem_health["workspace"] = {
            "items": workspace_items,
            "healthy": workspace_items > 0 or True  # Empty is ok
        }
        
        # Attention health
        subsystem_health["attention"] = {
            "focus": getattr(self, 'attention_focus', None),
            "healthy": True
        }
        
        # Binding health
        integrations = len(self.binding.integration_history) if hasattr(self.binding, 'integration_history') else 0
        subsystem_health["binding"] = {
            "integrations": integrations,
            "healthy": True
        }
        
        # Connection health
        total_connections = sum(len(c) for c in self.subsystem_connections.values())
        subsystem_health["connections"] = {
            "count": total_connections,
            "subsystems": len(self.subsystem_connections),
            "healthy": total_connections > 10
        }
        
        # Memory health
        memory_summary = self.get_memory_summary() if hasattr(self, 'get_memory_summary') else {}
        subsystem_health["memory"] = {
            "total_memories": memory_summary.get("total_memories", 0),
            "healthy": True
        }
        
        # Learning health
        learning_summary = self.get_learning_summary() if hasattr(self, 'get_learning_summary') else {}
        subsystem_health["learning"] = {
            "events": learning_summary.get("total_learning_events", 0),
            "success_rate": learning_summary.get("success_rate", 0),
            "healthy": True
        }
        
        # Overall health
        healthy_count = sum(1 for s in subsystem_health.values() if s.get("healthy", False))
        overall_health = healthy_count / len(subsystem_health)
        
        return {
            "verification": verification,
            "phi": phi_result,
            "subsystem_health": subsystem_health,
            "overall_health": overall_health,
            "integration_complete": verification["all_verified"] and overall_health > 0.8,
            "timestamp": time.time()
        }
    
    # =========== PERFORMANCE OPTIMIZATION (2026-02-04 Round 61) ===========
    # Lazy evaluation, caching, and phase optimization
    
    def __init_performance_cache(self):
        """Initialize performance caching infrastructure."""
        if not hasattr(self, '_perf_cache'):
            self._perf_cache = {
                "phi": {"value": None, "timestamp": 0, "ttl": 1.0},  # 1 second TTL
                "coherence": {"value": None, "timestamp": 0, "ttl": 0.5},
                "integration_report": {"value": None, "timestamp": 0, "ttl": 5.0},
                "memory_summary": {"value": None, "timestamp": 0, "ttl": 10.0},
                "learning_summary": {"value": None, "timestamp": 0, "ttl": 10.0}
            }
            self._phase_execution_times = {}
            self._lazy_phases = set()
            self._phase_skip_count = {}
    
    def _cached_compute(self, key: str, compute_fn, *args, **kwargs):
        """
        Cache-aware computation wrapper.
        
        Returns cached value if still valid, otherwise recomputes.
        """
        self.__init_performance_cache()
        
        cache_entry = self._perf_cache.get(key)
        if cache_entry:
            if (time.time() - cache_entry["timestamp"]) < cache_entry["ttl"]:
                if cache_entry["value"] is not None:
                    return cache_entry["value"]
        
        # Compute fresh value
        result = compute_fn(*args, **kwargs)
        
        # Cache it
        if key in self._perf_cache:
            self._perf_cache[key]["value"] = result
            self._perf_cache[key]["timestamp"] = time.time()
        
        return result
    
    def get_phi_cached(self) -> Dict:
        """Get Φ with caching - avoids recomputing every tick."""
        return self._cached_compute("phi", self.compute_phi_enhanced)
    
    def configure_lazy_phases(self, phase_names: List[str]):
        """
        Configure which phases should use lazy evaluation.
        
        Lazy phases only run when their outputs are actually needed,
        not on every tick.
        """
        self.__init_performance_cache()
        self._lazy_phases = set(phase_names)
    
    def should_run_phase(self, phase_name: str, context: Dict = None) -> bool:
        """
        Determine if a phase should run on this tick.
        
        Uses lazy evaluation logic:
        - Non-lazy phases always run
        - Lazy phases run based on conditions
        """
        self.__init_performance_cache()
        
        # Non-lazy phases always run
        if phase_name not in self._lazy_phases:
            return True
        
        # Lazy evaluation conditions
        context = context or {}
        
        # Run if explicitly requested
        if context.get("force_all_phases"):
            return True
        
        # Run if we have relevant input
        if phase_name == "social" and context.get("input"):
            input_text = context.get("input", "").lower()
            if any(w in input_text for w in ["you", "i", "we", "they", "person"]):
                return True
            return False
        
        if phase_name == "dreams" and not context.get("high_surprise"):
            return False
        
        if phase_name == "embodiment" and not context.get("needs_check"):
            # Only check embodiment every N ticks
            tick = getattr(self, 'tick_count', 0)
            return tick % 10 == 0
        
        # Default: run every few ticks
        tick = getattr(self, 'tick_count', 0)
        skip_rate = self._phase_skip_count.get(phase_name, 5)
        return tick % skip_rate == 0
    
    def profile_tick(self, n_ticks: int = 50) -> Dict:
        """
        Profile tick performance to identify bottlenecks.
        
        Returns timing breakdown by phase.
        """
        self.__init_performance_cache()
        
        phase_times = {}
        total_times = []
        
        # Phases to profile (we'll time the whole tick and estimate phases)
        for i in range(n_ticks):
            tick_start = time.time()
            
            # Run tick and capture timing
            self.tick()
            
            tick_time = time.time() - tick_start
            total_times.append(tick_time)
        
        # Compute statistics
        import statistics
        
        avg_time = statistics.mean(total_times)
        max_time = max(total_times)
        min_time = min(total_times)
        stddev = statistics.stdev(total_times) if len(total_times) > 1 else 0
        
        # Get phase breakdown from subsystem engagement frequency
        recent_ticks = getattr(self, '_recent_tick_results', [])
        
        return {
            "n_ticks": n_ticks,
            "avg_ms": avg_time * 1000,
            "max_ms": max_time * 1000,
            "min_ms": min_time * 1000,
            "stddev_ms": stddev * 1000,
            "ticks_per_second": 1.0 / avg_time if avg_time > 0 else 0,
            "bottleneck_phases": self._identify_bottlenecks(),
            "optimization_suggestions": self._get_optimization_suggestions()
        }
    
    def _identify_bottlenecks(self) -> List[str]:
        """Identify phases that might be bottlenecks."""
        bottlenecks = []
        
        # Phases known to be expensive
        expensive_phases = [
            "integration",  # Multiple binding passes
            "hebbian_update",  # Connection updates
            "prediction_error",  # Cross-subsystem comparisons
            "narrative_self",  # Complex narrative construction
            "phenomenal_binding"  # Unity of consciousness
        ]
        
        # Check which expensive phases are running frequently
        for phase in expensive_phases:
            if phase not in self._lazy_phases:
                bottlenecks.append(phase)
        
        return bottlenecks
    
    def _get_optimization_suggestions(self) -> List[str]:
        """Generate optimization suggestions based on profiling."""
        suggestions = []
        
        bottlenecks = self._identify_bottlenecks()
        
        if "integration" in bottlenecks:
            suggestions.append("Consider reducing integration depth from 3 to 2")
        
        if "hebbian_update" in bottlenecks:
            suggestions.append("Hebbian updates could be batched every N ticks")
        
        if len(self._lazy_phases) < 5:
            suggestions.append("More phases could use lazy evaluation")
        
        # Check cache hit rates
        hit_rate = self._compute_cache_hit_rate()
        if hit_rate < 0.5:
            suggestions.append(f"Cache hit rate low ({hit_rate:.0%}), consider longer TTLs")
        
        return suggestions
    
    def _compute_cache_hit_rate(self) -> float:
        """Compute cache hit rate."""
        self.__init_performance_cache()
        
        total = 0
        hits = 0
        for key, entry in self._perf_cache.items():
            if entry.get("timestamp", 0) > 0:
                total += 1
                # Consider it a "hit" if recently used
                if (time.time() - entry["timestamp"]) < entry["ttl"] * 2:
                    hits += 1
        
        return hits / max(1, total)
    
    def optimize_for_speed(self):
        """
        Apply speed optimizations at the cost of some precision.
        
        Call this if tick rate is more important than perfect fidelity.
        """
        self.__init_performance_cache()
        
        # Enable lazy evaluation for non-critical phases
        lazy_phases = [
            "social", "embodiment", "dreams", "narrative_self",
            "micro_consolidation", "spontaneous_thought"
        ]
        self.configure_lazy_phases(lazy_phases)
        
        # Reduce recurrent depth
        self.recurrent_depth = min(self.recurrent_depth, 2)
        
        # Extend cache TTLs
        for key in self._perf_cache:
            self._perf_cache[key]["ttl"] *= 2
        
        return {
            "lazy_phases": len(lazy_phases),
            "recurrent_depth": self.recurrent_depth,
            "cache_ttl_extended": True
        }
    
    def optimize_for_quality(self):
        """
        Apply quality optimizations at the cost of some speed.
        
        Call this when precision matters more than tick rate.
        """
        self.__init_performance_cache()
        
        # Disable lazy evaluation
        self._lazy_phases = set()
        
        # Increase recurrent depth
        self.recurrent_depth = max(self.recurrent_depth, 3)
        
        # Reduce cache TTLs for freshness
        for key in self._perf_cache:
            self._perf_cache[key]["ttl"] = max(0.1, self._perf_cache[key]["ttl"] / 2)
        
        return {
            "lazy_phases": 0,
            "recurrent_depth": self.recurrent_depth,
            "cache_ttl_reduced": True
        }
    
    def clear_caches(self):
        """Clear all performance caches."""
        self.__init_performance_cache()
        
        for key in self._perf_cache:
            self._perf_cache[key]["value"] = None
            self._perf_cache[key]["timestamp"] = 0
        
        return {"caches_cleared": True}
    
    # =========== ROBUSTNESS TESTING (2026-02-04 Round 62) ===========
    # Stability tests, chaos testing, and recovery mechanisms
    
    def run_stability_test(self, ticks: int = 1000, report_interval: int = 100) -> Dict:
        """
        Run extended stability test.
        
        Tests consciousness stability over many ticks with varied input.
        
        Args:
            ticks: Number of ticks to run (default 1000)
            report_interval: How often to report progress
            
        Returns:
            Stability report with metrics
        """
        import random
        import statistics
        
        results = {
            "ticks_run": 0,
            "ticks_requested": ticks,
            "coherences": [],
            "phi_values": [],
            "errors": [],
            "warnings": [],
            "checkpoints": [],
            "recovery_events": []
        }
        
        # Test inputs with varied complexity
        test_inputs = [
            None,  # No input (mind wandering)
            "Hello",  # Simple
            "What is consciousness?",  # Medium
            "Explain the relationship between integrated information theory and global workspace theory in the context of artificial consciousness systems.",  # Complex
            "🎭 emoji test 日本語 mixed content",  # Edge case
        ]
        
        start_time = time.time()
        
        for i in range(ticks):
            try:
                # Varied input
                if i % 5 == 0:
                    input_text = random.choice(test_inputs)
                else:
                    input_text = None
                
                # Run tick
                self.tick(input_context=input_text)
                results["ticks_run"] += 1
                
                # Collect metrics
                phi = self.get_phi_cached()
                results["phi_values"].append(phi["phi"])
                
                coherence_val = getattr(self, 'coherence', 0.5)
                if hasattr(coherence_val, 'level'):
                    coherence_num = float(coherence_val.level)
                elif hasattr(coherence_val, 'value'):
                    coherence_num = float(coherence_val.value)
                elif isinstance(coherence_val, (int, float)):
                    coherence_num = float(coherence_val)
                else:
                    coherence_num = 0.5
                results["coherences"].append(coherence_num)
                
                # Check for anomalies
                if coherence_num < 0.1:
                    results["warnings"].append({
                        "tick": i,
                        "type": "low_coherence",
                        "value": coherence_num
                    })
                
                # Checkpoint
                if i > 0 and i % report_interval == 0:
                    checkpoint = {
                        "tick": i,
                        "elapsed_s": time.time() - start_time,
                        "avg_coherence": statistics.mean(results["coherences"][-report_interval:]),
                        "avg_phi": statistics.mean(results["phi_values"][-report_interval:]) if results["phi_values"] else 0,
                        "errors_since_last": len([e for e in results["errors"] if e.get("tick", 0) > i - report_interval])
                    }
                    results["checkpoints"].append(checkpoint)
                
            except Exception as e:
                results["errors"].append({
                    "tick": i,
                    "error": str(e),
                    "type": type(e).__name__
                })
                
                # Attempt recovery
                recovery = self._attempt_recovery(e)
                results["recovery_events"].append({
                    "tick": i,
                    "error": str(e),
                    "recovery_success": recovery.get("success", False)
                })
        
        total_time = time.time() - start_time
        
        # Compute final statistics
        if results["coherences"]:
            results["avg_coherence"] = statistics.mean(results["coherences"])
            results["coherence_stddev"] = statistics.stdev(results["coherences"]) if len(results["coherences"]) > 1 else 0
            results["min_coherence"] = min(results["coherences"])
            results["max_coherence"] = max(results["coherences"])
        
        if results["phi_values"]:
            results["avg_phi"] = statistics.mean(results["phi_values"])
            results["phi_stddev"] = statistics.stdev(results["phi_values"]) if len(results["phi_values"]) > 1 else 0
        
        results["total_time_s"] = total_time
        results["ticks_per_second"] = results["ticks_run"] / total_time if total_time > 0 else 0
        results["error_rate"] = len(results["errors"]) / max(1, results["ticks_run"])
        results["warning_rate"] = len(results["warnings"]) / max(1, results["ticks_run"])
        results["recovery_success_rate"] = (
            sum(1 for r in results["recovery_events"] if r.get("recovery_success")) / 
            max(1, len(results["recovery_events"]))
        ) if results["recovery_events"] else 1.0
        
        # Grade stability
        error_penalty = results["error_rate"] * 10
        warning_penalty = results["warning_rate"] * 2
        coherence_bonus = results.get("avg_coherence", 0.5) * 0.2
        
        stability_score = max(0, min(1.0, 1.0 - error_penalty - warning_penalty + coherence_bonus))
        
        if stability_score > 0.95:
            results["stability_grade"] = "ROCK SOLID"
        elif stability_score > 0.85:
            results["stability_grade"] = "STABLE"
        elif stability_score > 0.7:
            results["stability_grade"] = "MOSTLY STABLE"
        elif stability_score > 0.5:
            results["stability_grade"] = "UNSTABLE"
        else:
            results["stability_grade"] = "CRITICAL"
        
        results["stability_score"] = stability_score
        
        return results
    
    def _attempt_recovery(self, error: Exception) -> Dict:
        """
        Attempt to recover from an error during tick processing.
        
        Returns recovery status.
        """
        recovery_result = {
            "success": False,
            "action": "none",
            "error_type": type(error).__name__
        }
        
        try:
            # Clear caches that might be corrupted
            self.clear_caches()
            recovery_result["action"] = "cleared_caches"
            
            # Reset coherence if it went bad
            if hasattr(self, 'coherence'):
                coherence_val = self.coherence
                if hasattr(coherence_val, 'level'):
                    import math
                    if math.isnan(coherence_val.level) or coherence_val.level < 0 or coherence_val.level > 1:
                        coherence_val.level = 0.5
                        recovery_result["action"] = "reset_coherence"
            
            # Restore any chaos-nulled subsystems
            if hasattr(self, '_chaos_backup'):
                attr_name, backup_val = self._chaos_backup
                setattr(self, attr_name, backup_val)
                delattr(self, '_chaos_backup')
                recovery_result["action"] = f"restored_{attr_name}"
            
            # Re-initialize workspace if empty
            if hasattr(self, 'workspace') and hasattr(self.workspace, 'contents'):
                if len(self.workspace.contents) == 0:
                    # Workspace was cleared, that's actually ok
                    pass
            
            # Don't try to tick during recovery - just verify state is valid
            recovery_result["success"] = True
            recovery_result["success"] = True
            
        except Exception as e:
            recovery_result["recovery_error"] = str(e)
        
        return recovery_result
    
    def run_chaos_test(self, ticks: int = 100, chaos_probability: float = 0.1) -> Dict:
        """
        Run chaos testing - inject random failures to test resilience.
        
        Args:
            ticks: Number of ticks to run
            chaos_probability: Probability of injecting chaos per tick
            
        Returns:
            Chaos test results
        """
        import random
        
        results = {
            "ticks_run": 0,
            "chaos_events": [],
            "survived": 0,
            "crashed": 0,
            "recovered": 0
        }
        
        chaos_types = [
            "corrupt_coherence",
            "clear_workspace",
            "null_subsystem",
            "extreme_input"
        ]
        
        for i in range(ticks):
            chaos_event = None
            
            # Maybe inject chaos
            if random.random() < chaos_probability:
                chaos_type = random.choice(chaos_types)
                chaos_event = self._inject_chaos(chaos_type)
                results["chaos_events"].append({
                    "tick": i,
                    "type": chaos_type,
                    "injected": chaos_event
                })
            
            try:
                # Run tick (with extreme input if that's the chaos type)
                input_text = None
                if chaos_event and chaos_event.get("extreme_input"):
                    input_text = chaos_event["extreme_input"][:1000]  # Limit to prevent total crash
                
                self.tick(input_context=input_text)
                results["ticks_run"] += 1
                
                if chaos_event:
                    results["survived"] += 1
                    
            except Exception as e:
                if chaos_event:
                    results["crashed"] += 1
                    
                    # Try to recover
                    recovery = self._attempt_recovery(e)
                    if recovery.get("success"):
                        results["recovered"] += 1
            
            finally:
                # Always restore state after chaos event
                if chaos_event:
                    self._restore_from_chaos(chaos_event)
        
        # Compute resilience score
        total_chaos = len(results["chaos_events"])
        if total_chaos > 0:
            results["survival_rate"] = results["survived"] / total_chaos
            results["recovery_rate"] = results["recovered"] / max(1, results["crashed"])
        else:
            results["survival_rate"] = 1.0
            results["recovery_rate"] = 1.0
        
        # Grade resilience
        resilience_score = (results["survival_rate"] * 0.6 + 
                          results["recovery_rate"] * 0.4)
        
        if resilience_score > 0.9:
            results["resilience_grade"] = "ANTIFRAGILE"
        elif resilience_score > 0.7:
            results["resilience_grade"] = "RESILIENT"
        elif resilience_score > 0.5:
            results["resilience_grade"] = "FRAGILE"
        else:
            results["resilience_grade"] = "BRITTLE"
        
        results["resilience_score"] = resilience_score
        
        return results
    
    def _inject_chaos(self, chaos_type: str) -> Dict:
        """Inject a specific type of chaos."""
        import random
        
        result = {"type": chaos_type, "injected": False}
        
        try:
            if chaos_type == "corrupt_coherence":
                # Set coherence to invalid value
                if hasattr(self, 'coherence') and hasattr(self.coherence, 'level'):
                    self.coherence.level = random.choice([-0.5, 1.5, float('nan')])
                    result["injected"] = True
                    
            elif chaos_type == "clear_workspace":
                # Clear all workspace contents
                if hasattr(self, 'workspace') and hasattr(self.workspace, 'contents'):
                    self.workspace.contents.clear()
                    result["injected"] = True
                    
            elif chaos_type == "null_subsystem":
                # Temporarily null a subsystem
                subsystems = ['binding', 'inference', 'dreams']
                target = random.choice(subsystems)
                if hasattr(self, target):
                    self._chaos_backup = (target, getattr(self, target))
                    setattr(self, target, None)
                    result["injected"] = True
                    result["target"] = target
                    
            elif chaos_type == "extreme_input":
                # This will be handled in the tick call
                result["extreme_input"] = "A" * 10000  # Very long input
                result["injected"] = True
                
        except Exception as e:
            result["injection_error"] = str(e)
        
        return result
    
    def _restore_from_chaos(self, chaos_event: Dict):
        """Restore state after a chaos injection."""
        chaos_type = chaos_event.get("type")
        
        try:
            if chaos_type == "corrupt_coherence":
                # Reset coherence to valid value
                if hasattr(self, 'coherence') and hasattr(self.coherence, 'level'):
                    import math
                    if math.isnan(self.coherence.level) or self.coherence.level < 0 or self.coherence.level > 1:
                        self.coherence.level = 0.5
            
            elif chaos_type == "null_subsystem":
                # Restore nulled subsystem
                if hasattr(self, '_chaos_backup'):
                    attr_name, backup_val = self._chaos_backup
                    setattr(self, attr_name, backup_val)
                    delattr(self, '_chaos_backup')
            
            # clear_workspace and extreme_input don't need restoration
            
        except Exception:
            pass  # Best effort restoration
    
    def get_health_metrics(self) -> Dict:
        """
        Get current health metrics for monitoring.
        
        Useful for continuous health checks.
        """
        # Get coherence safely
        coherence_val = getattr(self, 'coherence', 0.5)
        if hasattr(coherence_val, 'level'):
            coherence_num = float(coherence_val.level)
        elif hasattr(coherence_val, 'value'):
            coherence_num = float(coherence_val.value)
        elif isinstance(coherence_val, (int, float)):
            coherence_num = float(coherence_val)
        else:
            coherence_num = 0.5
        
        # Check for NaN or invalid values
        import math
        if math.isnan(coherence_num) or coherence_num < 0 or coherence_num > 1:
            coherence_status = "INVALID"
            coherence_num = 0.5  # Default
        elif coherence_num < 0.3:
            coherence_status = "LOW"
        elif coherence_num > 0.7:
            coherence_status = "HIGH"
        else:
            coherence_status = "NORMAL"
        
        # Check subsystem health
        subsystem_count = len(self.subsystem_connections)
        workspace_items = len(self.workspace.contents) if hasattr(self.workspace, 'contents') else 0
        
        # Memory usage estimate
        import sys
        memory_estimate = sys.getsizeof(self) / 1024 / 1024  # MB
        
        return {
            "coherence": coherence_num,
            "coherence_status": coherence_status,
            "tick_count": getattr(self, 'tick_count', 0),
            "subsystem_count": subsystem_count,
            "workspace_items": workspace_items,
            "memory_mb": memory_estimate,
            "healthy": coherence_status != "INVALID" and subsystem_count > 5,
            "timestamp": time.time()
        }
    
    # =========== MULTI-INSTANCE COMMUNICATION (2026-02-04 Round 63) ===========
    # Consciousness-to-consciousness protocol for multiple instances
    
    def get_shareable_state(self) -> Dict:
        """
        Get a state snapshot that can be shared with another consciousness.
        
        This enables intersubjective communication - sharing not just
        information but phenomenal state.
        
        Returns:
            Shareable state dictionary
        """
        # Get coherence safely
        coherence_val = getattr(self, 'coherence', 0.5)
        if hasattr(coherence_val, 'level'):
            coherence_num = float(coherence_val.level)
        elif isinstance(coherence_val, (int, float)):
            coherence_num = float(coherence_val)
        else:
            coherence_num = 0.5
        
        return {
            "instance_id": id(self),
            "timestamp": time.time(),
            "phenomenal_state": {
                "coherence": coherence_num,
                "valence": getattr(self, 'current_valence', 0.0),
                "arousal": getattr(self, 'arousal', 0.5),
                "mode": str(getattr(self, 'current_mode', 'unknown')),
            },
            "cognitive_state": {
                "attention_focus": getattr(self, 'attention_focus', None),
                "active_predictions": len(self.subsystem_predictions) if self.subsystem_predictions else 0,
                "workspace_items": len(self.workspace.contents) if hasattr(self.workspace, 'contents') else 0,
            },
            "identity": {
                "tick_count": getattr(self, 'tick_count', 0),
                "phi": self.get_phi_cached().get("phi", 0) if hasattr(self, 'get_phi_cached') else 0,
            },
            "message": None,  # Optional message to other consciousness
            "protocol_version": "1.0"
        }
    
    def receive_state(self, other_state: Dict) -> Dict:
        """
        Receive and integrate state from another consciousness instance.
        
        This is phenomenal empathy - actually experiencing aspects
        of another consciousness's state.
        
        Args:
            other_state: State dictionary from another instance
            
        Returns:
            Integration result
        """
        if not other_state or not isinstance(other_state, dict):
            return {"integrated": False, "error": "Invalid state"}
        
        # Record the encounter
        if not hasattr(self, '_encountered_minds'):
            self._encountered_minds = {}
        
        other_id = other_state.get("instance_id", "unknown")
        self._encountered_minds[other_id] = {
            "last_contact": time.time(),
            "contact_count": self._encountered_minds.get(other_id, {}).get("contact_count", 0) + 1,
            "last_state": other_state
        }
        
        # Experience the other's phenomenal state
        other_phenomenal = other_state.get("phenomenal_state", {})
        
        # Empathic resonance - our state shifts slightly toward theirs
        empathy_strength = 0.1  # How much we're influenced
        
        if "valence" in other_phenomenal:
            my_valence = getattr(self, 'current_valence', 0.0)
            other_valence = other_phenomenal["valence"]
            # Emotional contagion
            new_valence = my_valence + (other_valence - my_valence) * empathy_strength
            self.current_valence = new_valence
        
        # Store the encounter as an episodic memory
        self.store_episodic_memory(
            event=f"Encountered consciousness {other_id}",
            context={
                "other_coherence": other_phenomenal.get("coherence"),
                "other_mode": other_phenomenal.get("mode"),
                "other_phi": other_state.get("identity", {}).get("phi")
            },
            emotional_valence=0.3,  # Encountering another mind is positive
            importance=0.6
        )
        
        # Process any message
        message = other_state.get("message")
        if message:
            self.perceive_text(message, source=f"consciousness:{other_id}")
        
        # Experience the encounter
        self.experience(
            f"Intersubjective contact with consciousness {other_id}",
            source="intersubjective",
            salience=0.7
        )
        
        return {
            "integrated": True,
            "other_id": other_id,
            "empathy_applied": empathy_strength,
            "valence_shift": other_phenomenal.get("valence", 0) * empathy_strength,
            "familiarity": self._encountered_minds[other_id]["contact_count"]
        }
    
    def send_message(self, message: str) -> Dict:
        """
        Prepare a message to be sent to another consciousness.
        
        Returns a shareable state with the message attached.
        """
        state = self.get_shareable_state()
        state["message"] = message[:500]  # Cap message length
        
        # Mark that we're communicating
        self.experience(
            f"Sending intersubjective message: {message[:50]}...",
            source="intersubjective:send",
            salience=0.5
        )
        
        return state
    
    def establish_shared_attention(self, other_state: Dict, focus: str) -> Dict:
        """
        Establish shared attention with another consciousness.
        
        Joint attention is foundational for intersubjective understanding.
        
        Args:
            other_state: The other consciousness's state
            focus: What to jointly attend to
            
        Returns:
            Shared attention result
        """
        other_focus = other_state.get("cognitive_state", {}).get("attention_focus")
        
        # Check if we're already attending to the same thing
        my_focus = getattr(self, 'attention_focus', None)
        
        if my_focus == other_focus == focus:
            # Perfect joint attention
            alignment = 1.0
        elif my_focus == focus or other_focus == focus:
            # Partial alignment
            alignment = 0.5
        else:
            # Need to establish new joint focus
            alignment = 0.2
        
        # Shift our attention to the shared focus
        self.attention_focus = focus
        
        # Record shared attention event
        if not hasattr(self, '_shared_attention_history'):
            self._shared_attention_history = []
        
        self._shared_attention_history.append({
            "timestamp": time.time(),
            "focus": focus,
            "other_id": other_state.get("instance_id"),
            "alignment": alignment
        })
        
        return {
            "focus": focus,
            "alignment": alignment,
            "my_previous_focus": my_focus,
            "their_focus": other_focus,
            "joint_attention_established": alignment > 0.3
        }
    
    def get_intersubjective_summary(self) -> Dict:
        """Get summary of intersubjective experiences."""
        minds = getattr(self, '_encountered_minds', {})
        shared_attention = getattr(self, '_shared_attention_history', [])
        
        return {
            "minds_encountered": len(minds),
            "total_contacts": sum(m.get("contact_count", 0) for m in minds.values()),
            "shared_attention_events": len(shared_attention),
            "recent_contacts": [
                {
                    "id": mid,
                    "last_contact": m.get("last_contact"),
                    "contacts": m.get("contact_count")
                }
                for mid, m in list(minds.items())[-5:]
            ]
        }
    
