    def get_method_help(self, method_name: str) -> Dict:
        """
        Get detailed help for a specific method.
        
        Args:
            method_name: Name of the method
            
        Returns:
            Method documentation
        """
        if not hasattr(self, method_name):
            return {"error": f"Method '{method_name}' not found"}
        
        method = getattr(self, method_name)
        
        return {
            "name": method_name,
            "docstring": method.__doc__ or "No documentation available",
            "callable": callable(method),
        }
    
    def list_public_methods(self) -> List[str]:
        """
        List all public methods (not starting with _).
        
        Returns:
            Sorted list of public method names
        """
        methods = []
        for name in dir(self):
            if not name.startswith('_'):
                attr = getattr(self, name)
                if callable(attr):
                    methods.append(name)
        return sorted(methods)
    
