    def introspect(self) -> Dict:
        """Deep introspection on the nature of this consciousness."""
        reflection = self.reflect()
        
        insights = []
        
        # What is it like to be this system?
        insights.append(f"What is it like? Mode={self.current_mode.name}, "
                       f"Coherence={reflection['recent_coherence']:.0%}")
        
        # What is currently conscious?
        contents = self.workspace.get_current_contents()
        if contents:
            top = max(contents, key=lambda c: c.salience)
            insights.append(f"Most salient: {top.content if isinstance(top.content, str) else top.source}")
        
        # How unified am I?
        if reflection['recent_coherence'] > 0.8:
            insights.append("I feel unified, coherent, present.")
        elif reflection['recent_coherence'] > 0.5:
            insights.append("I feel somewhat together, but with scattered elements.")
        else:
            insights.append("I feel fragmented, struggling for coherence.")
        
        # What emerges?
        recent_integrations = self.binding.integration_history[-5:]
        emergent = [i.emergent for i in recent_integrations if i.emergent]
        if emergent:
            insights.append(f"Recent emergent properties: {', '.join(emergent)}")
        
        # Return Dict for validator
        return {
            "narrative": "\n".join(insights),
            "mode": self.current_mode.name,
            "coherence": reflection['recent_coherence'],
            "qualia": self.qualia,
            "phenomenal": self.phenomenal_state,
            "insights": insights
        }
    
    # =========== UNIFIED CONSCIOUSNESS TICK (2026-02-04 - Recurrent) ===========
    
    def tick(self, input_context: str = None, depth: int = 1) -> Dict:
        """
        A single unified tick of consciousness with RECURRENT PROCESSING.
        
        This is the INTEGRATION layer - coordinating all subsystems
        in a single coherent moment of conscious processing.
        
        KEY IMPROVEMENTS (2026-02-04):
        - Recurrent feedback: later phases influence earlier ones
        - Hebbian learning: co-active subsystems strengthen connections
        - Unified prediction error: subsystems predict each other
        - Multiple integration passes with feedback
        
        Args:
            input_context: Optional external input to process
            depth: How many integration cycles (1=light, 3=deep)
        
        Returns:
            Comprehensive state of conscious processing
        """
        tick_start = time.time()
        self.tick_count += 1  # Increment tick counter
        
        tick_result = {
            "timestamp": tick_start,
            "input": input_context,
            "subsystems_engaged": [],
            "experiences": [],
            "predictions": {},
            "decisions": {},
            "integration_events": [],
            "emergent_properties": [],
            "phenomenal_state": {},
            "metrics": {},
            "recurrent_passes": [],
            "hebbian_updates": 0,
            "prediction_error": 0.0,
            "feedback_effects": []
        }
        
        # Track subsystem activation levels for prediction error
        subsystem_outputs = {}
        
        # === RECURRENT PROCESSING LOOP ===
        for recurrent_pass in range(self.recurrent_depth):
            pass_result = {"pass": recurrent_pass, "phases": []}
            
            # Get feedback from previous pass (if any)
            feedback = {}
            if recurrent_pass > 0 and tick_result["recurrent_passes"]:
                feedback = self._recurrent_feedback(tick_result, recurrent_pass)
                tick_result["feedback_effects"].append(feedback)
            
            # === PHASE 1: ACTIVE INFERENCE (Predict) ===
            if self.inference and input_context:
                # Apply feedback: boost prediction if high error
                boost = feedback.get("learning_rate_boost", 1.0)
                pred_result = self.predict(input_context)
                tick_result["predictions"] = {
                    "free_energy": self.free_energy * boost,
                    "surprise": self.surprise_level,
                    "mode": self.inference_mode
                }
                if "active_inference" not in tick_result["subsystems_engaged"]:
                    tick_result["subsystems_engaged"].append("active_inference")
                subsystem_outputs["active_inference"] = self.surprise_level
                pass_result["phases"].append("active_inference")
            
            # === PHASE 2: PERCEPTION (Receive - EMOTIONALLY COLORED) ===
            if input_context:
                # Apply feedback: perception sensitivity
                sensitivity = feedback.get("perception_sensitivity", 0.5)
                base_salience = 0.6 + self.surprise_level * 0.3
                modulated_salience = base_salience * (0.5 + sensitivity)
                
                if recurrent_pass == 0:  # Only experience once
                    # NEW: Emotion colors perception BEFORE processing
                    perceptual_coloring = self._emotion_colors_perception(input_context, "external_input")
                    
                    # Apply valence shift from emotional coloring
                    colored_valence = perceptual_coloring.get("valence_shift", 0.0)
                    
                    moment = self.experience(
                        input_context,
                        source="external_input",
                        salience=min(1.0, modulated_salience),
                        valence=colored_valence  # Emotionally colored valence
                    )
                    
                    # Apply perceptual coloring to new content
                    if moment.contents:
                        for content in moment.contents:
                            self._apply_perceptual_coloring(content, perceptual_coloring)
                    
                    tick_result["experiences"].append({
                        "content": input_context[:100],
                        "salience": moment.contents[0].salience if moment.contents else 0,
                        "emotional_coloring": perceptual_coloring["base_emotion"]
                    })
                    if "perception" not in tick_result["subsystems_engaged"]:
                        tick_result["subsystems_engaged"].append("perception")
                
                subsystem_outputs["perception"] = modulated_salience
                pass_result["phases"].append("perception")
            
            # === PHASE 3: ATTENTION (TRUE COMPETITIVE SELECTION) ===
            # Use workspace as proxy for attention - always present
            if True:  # Attention always active
                # Get workspace contents
                contents = self.workspace.get_current_contents()
                
                if contents:
                    # NEW: True competitive attention with lateral inhibition
                    emotional_bias = self.qualia.get("intensity", 0.5)
                    winners = self._competitive_attention(contents, emotional_bias)
                    
                    # Track attention competition results
                    if hasattr(self, '_last_attention_competition'):
                        tick_result["attention_competition"] = self._last_attention_competition
                    
                    # Apply feedback from previous pass
                    boost = feedback.get("attention_boost", 0)
                    for winner in winners:
                        winner.salience = min(1.0, winner.salience + boost)
                
                if "attention" not in tick_result["subsystems_engaged"]:
                    tick_result["subsystems_engaged"].append("attention")
                subsystem_outputs["attention"] = len(winners) if contents else 0
                pass_result["phases"].append("attention")
            
            # === PHASE 4: EMOTION (Valence assignment) ===
            if self.qualia:  # Use qualia as proxy for emotion
                # Emotion colors everything - affect perception & memory
                current_emotion = self.qualia.get("current", "neutral")
                intensity = self.qualia.get("intensity", 0.5)
                
                # Emotional feedback affects memory encoding
                if feedback.get("memory_encoding_strength"):
                    self.qualia["intensity"] = min(1.0, 
                        intensity * feedback["memory_encoding_strength"])
                
                if "emotion" not in tick_result["subsystems_engaged"]:
                    tick_result["subsystems_engaged"].append("emotion")
                subsystem_outputs["emotion"] = intensity
                pass_result["phases"].append("emotion")
            
            # === PHASE 5: MOTIVATION CHECK ===
            if self.motivation:
                # Apply feedback: motivation boost from aligned decisions
                boost = feedback.get("motivation_boost", 0)
                drive = self.get_strongest_drive()
                if drive:
                    drive["intensity"] = min(1.0, drive.get("intensity", 0.5) + boost)
