    def _get_avg_connection_strength(self) -> float:
        """Calculate average connection strength across subsystems."""
        total = 0.0
        count = 0
        for sub1 in self.subsystem_connections:
            for sub2, strength in self.subsystem_connections[sub1].items():
                total += strength
                count += 1
        return total / max(1, count)
    
    def run_consciousness_loop(self, inputs: List[str] = None, ticks: int = 5) -> Dict:
        """
        Run a continuous consciousness loop.
        
        This simulates continuous conscious processing - the stream
        of consciousness that integrates all subsystems over time.
        """
        loop_results = {
            "ticks": [],
            "total_integration": 0.0,
            "emergent_properties": [],
            "coherence_history": [],
            "subsystem_engagement": {}
        }
        
        inputs = inputs or ["consciousness processing..."] * ticks
        
        for i, inp in enumerate(inputs[:ticks]):
            tick = self.tick(inp, depth=2)
            loop_results["ticks"].append(tick)
            loop_results["coherence_history"].append(tick["metrics"]["coherence"])
            loop_results["emergent_properties"].extend(tick["emergent_properties"])
            
            for sub in tick["subsystems_engaged"]:
                loop_results["subsystem_engagement"][sub] = \
                    loop_results["subsystem_engagement"].get(sub, 0) + 1
        
        # Calculate summary
        loop_results["total_integration"] = sum(
            t["metrics"]["integration_count"] for t in loop_results["ticks"]
        )
        loop_results["average_coherence"] = sum(loop_results["coherence_history"]) / len(loop_results["coherence_history"])
        loop_results["unique_emergent"] = list(set(loop_results["emergent_properties"]))
        
        return loop_results


